const Q_SEC_SCIENCE=[{"id": "sds71001", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which of these is a characteristic shared by ALL living things?", "options": ["they can fly", "they reproduce", "they have green colouring", "they live in water"], "answer": 1, "exp": "All living things share certain characteristics, including the ability to reproduce, along with growth, movement, and responding to their environment.", "hint": "Think about a characteristic that applies to every single living thing, from bacteria to elephants."}, {"id": "sds71002", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "A classification key asks: 'Does it have a backbone?' A jellyfish would answer:", "options": ["yes", "no", "sometimes", "the question doesn't apply to jellyfish"], "answer": 1, "exp": "A jellyfish is an invertebrate, meaning it does not have a backbone, so it would answer 'no' to this question.", "hint": "Think about whether a jellyfish has any bones inside its body at all."}, {"id": "sds71003", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which of these is the basic unit of life?", "options": ["the organ", "the tissue", "the cell", "the organism"], "answer": 2, "exp": "The cell is considered the basic structural and functional unit of all living things.", "hint": "This is the smallest unit that can be considered 'alive' on its own."}, {"id": "sds71004", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which structure in a cell controls most of the cell's activities and contains its genetic material?", "options": ["the cell membrane", "the nucleus", "the cytoplasm", "the cell wall"], "answer": 1, "exp": "The nucleus contains the cell's genetic material (DNA) and controls most of its activities.", "hint": "Think about the structure that acts like the 'control centre' of the cell."}, {"id": "sds71005", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which structure is found in plant cells but NOT in animal cells?", "options": ["nucleus", "cytoplasm", "cell wall", "cell membrane"], "answer": 2, "exp": "Plant cells have a rigid cell wall surrounding the cell membrane, providing structure and support, while animal cells do not have this structure.", "hint": "Think about what gives plant cells their rigid, structured shape."}, {"id": "sds71006", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "What is the main function of chloroplasts in plant cells?", "options": ["to control the cell's activities", "to capture light energy for photosynthesis", "to store waste products", "to provide structural support"], "answer": 1, "exp": "Chloroplasts contain chlorophyll, which captures light energy, allowing the plant to carry out photosynthesis.", "hint": "Think about the green colour of plants and what process that colour is involved in."}, {"id": "sds71007", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which of these organisms is unicellular (made of only one cell)?", "options": ["a human", "an oak tree", "a bacterium", "a whale"], "answer": 2, "exp": "A bacterium is a unicellular organism, made of just a single cell, unlike humans, trees and whales which are multicellular.", "hint": "Think about which of these organisms is far too simple to need more than one cell."}, {"id": "sds71008", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells — Tools", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which tool is used to view cells that are too small to see with the naked eye?", "options": ["a telescope", "a microscope", "a magnifying glass only", "a periscope"], "answer": 1, "exp": "A microscope uses lenses to magnify very small objects, such as cells, far beyond what the naked eye or a simple magnifying glass can show.", "hint": "This tool is specifically designed to magnify extremely small objects, like cells."}, {"id": "sds71009", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells — Tools", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Under a microscope, a cell that is actually 0.05 mm wide appears to be 5 mm wide. How many times has it been magnified?", "options": ["10 times", "50 times", "100 times", "500 times"], "answer": 2, "exp": "Step 1: Divide the magnified size by the real size: 5 ÷ 0.05. Step 2: 5 ÷ 0.05 = 100 times.", "hint": "Divide the size seen under the microscope by the actual real size."}, {"id": "sds71010", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which group does a mushroom belong to?", "options": ["plant", "animal", "fungus", "bacteria"], "answer": 2, "exp": "A mushroom is a fungus, a separate kingdom from plants and animals, which gets nutrients by breaking down organic matter rather than photosynthesising.", "hint": "This organism doesn't photosynthesise like a plant, but isn't an animal either."}, {"id": "sds71011", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "What is a 'dichotomous key' used for in classification?", "options": ["to measure an organism's size", "to sort organisms step by step using a series of either/or questions", "to record an organism's colour only", "to count the number of organisms in a habitat"], "answer": 1, "exp": "A dichotomous key sorts organisms using a series of either/or (two-choice) questions, leading step by step to an identification.", "hint": "This type of key always offers exactly two choices at each step."}, {"id": "sds71012", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which kingdom do animals belong to?", "options": ["Plantae", "Animalia", "Fungi", "Monera"], "answer": 1, "exp": "Animals belong to the kingdom Animalia, one of the major groups used to classify living things.", "hint": "This kingdom's name closely resembles the English word for these organisms."}, {"id": "sds71013", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which of these best describes the function of the cell membrane?", "options": ["it controls what substances enter and leave the cell", "it produces energy for the cell", "it stores the cell's genetic material", "it captures light energy"], "answer": 0, "exp": "The cell membrane acts as a selective barrier, controlling which substances can enter or leave the cell.", "hint": "Think about the structure that forms the outer boundary of the cell, controlling movement in and out."}, {"id": "sds71014", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which organelle is often called the 'powerhouse' of the cell because it produces energy?", "options": ["the nucleus", "the mitochondria", "the cell wall", "the vacuole"], "answer": 1, "exp": "Mitochondria release energy from food through a process called respiration, earning them the nickname 'powerhouse of the cell'.", "hint": "This structure is responsible for releasing usable energy within the cell."}, {"id": "sds71015", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which of these is an example of an invertebrate?", "options": ["a snake", "a frog", "a spider", "a kangaroo"], "answer": 2, "exp": "A spider is an invertebrate, meaning it does not have a backbone, unlike snakes, frogs and kangaroos, which are all vertebrates.", "hint": "Think about which of these animals does not have a backbone."}, {"id": "sds71016", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "What is the main difference between a unicellular and a multicellular organism?", "options": ["unicellular organisms are always larger", "multicellular organisms are made of many cells working together, while unicellular organisms are made of just one", "unicellular organisms cannot move at all", "multicellular organisms never reproduce"], "answer": 1, "exp": "Multicellular organisms are made of many cells that work together, performing different functions, while unicellular organisms consist of just a single cell.", "hint": "Think about the literal meaning of the prefixes 'uni-' (one) and 'multi-' (many)."}, {"id": "sds71017", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which structure stores water, nutrients, and waste products in a plant cell?", "options": ["the nucleus", "the vacuole", "the cell wall", "the chloroplast"], "answer": 1, "exp": "The vacuole is a large, fluid-filled structure in plant cells used for storing water, nutrients, and waste products.", "hint": "This structure is often the largest single structure visible inside a plant cell."}, {"id": "sds71018", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which of these is NOT one of the seven main characteristics typically used to identify living things?", "options": ["movement", "reproduction", "colour", "respiration"], "answer": 2, "exp": "Colour is not one of the standard characteristics used to define living things; movement, reproduction and respiration are all examples of genuine life processes.", "hint": "Think about which option is just a physical trait, rather than a process all living things carry out."}, {"id": "sds71019", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "A classification key sorts insects by asking: 'Does it have wings?' then 'Does it have a stinger?' A bee (winged, with a stinger) would follow which path?", "options": ["no wings, no stinger", "wings, no stinger", "no wings, stinger", "wings, stinger"], "answer": 3, "exp": "A bee has wings and a stinger, so it follows the 'wings' branch, then the 'stinger' branch.", "hint": "Check both characteristics described for a bee against the two-question key."}, {"id": "sds71020", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "What is the function of ribosomes in a cell?", "options": ["they produce proteins", "they store genetic material", "they provide structural support only", "they capture light energy"], "answer": 0, "exp": "Ribosomes are the structures within a cell responsible for producing proteins, following instructions from the genetic material.", "hint": "This structure 'builds' something essential for the cell's many functions."}, {"id": "sds71021", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells — Levels of Organisation", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which best describes the relationship between cells, tissues, organs, and organisms, from smallest to largest?", "options": ["organism, organ, tissue, cell", "cell, tissue, organ, organism", "tissue, cell, organism, organ", "organ, organism, cell, tissue"], "answer": 1, "exp": "The correct order from smallest to largest is: cell (basic unit), tissue (group of similar cells), organ (group of tissues), and organism (a complete living thing made of organs).", "hint": "Start with the smallest structural unit and build up step by step."}, {"id": "sds71022", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which group of organisms is described as 'prokaryotic', meaning they lack a nucleus?", "options": ["plants", "animals", "fungi", "bacteria"], "answer": 3, "exp": "Bacteria are prokaryotic organisms, meaning their cells lack a true nucleus, unlike plants, animals and fungi, which are eukaryotic.", "hint": "Think about the simplest, most ancient type of single-celled organism."}, {"id": "sds71023", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Why might a scientist use a classification key rather than just guessing an organism's identity?", "options": ["it guarantees the organism will be rare", "it provides a systematic, repeatable method for accurately identifying organisms", "it is faster than any other method", "it only works for plants"], "answer": 1, "exp": "A classification key provides a systematic, step-by-step method that any scientist can repeat and rely on for accurate identification, rather than relying on guesswork.", "hint": "Think about the benefits of having a consistent, repeatable method, rather than relying on guesswork."}, {"id": "sds71024", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Classification", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "Which of these correctly lists the five kingdoms typically used in classification?", "options": ["Animalia, Plantae, Fungi, Protista, Monera", "Animalia, Plantae, Insecta, Reptilia, Mammalia", "Vertebrates, Invertebrates, Plants, Fungi, Bacteria", "Mammals, Birds, Fish, Reptiles, Amphibians"], "answer": 0, "exp": "The five-kingdom classification system includes Animalia, Plantae, Fungi, Protista, and Monera.", "hint": "The correct list includes broad categories like Fungi and Protista, not specific animal groups."}, {"id": "sds71025", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Cells", "difficulty": "medium", "style": "standard", "paper": "G7-S1", "q": "What is the main role of the cytoplasm within a cell?", "options": ["it is the jelly-like substance where most cell activities take place", "it stores genetic material", "it controls movement of substances in and out of the cell", "it captures light energy"], "answer": 0, "exp": "The cytoplasm is the jelly-like substance filling the cell, where many of the cell's chemical processes take place.", "hint": "Think about the substance that fills most of the space inside a cell, surrounding its other structures."}, {"id": "sds72001", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which of these is a pure substance, not a mixture?", "options": ["salt water", "air", "oxygen gas", "orange juice"], "answer": 2, "exp": "Oxygen gas is a pure substance, made of only one type of particle, while salt water, air and orange juice are all mixtures of different substances.", "hint": "A pure substance contains only one type of particle, with nothing else mixed in."}, {"id": "sds72002", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Separating Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which separating technique would best separate sand from water?", "options": ["filtration", "distillation", "magnetism", "evaporation only"], "answer": 0, "exp": "Filtration uses a filter to separate insoluble solid particles (like sand) from a liquid, allowing the water to pass through while the sand is trapped.", "hint": "Think about using a barrier with tiny holes to trap solid particles while liquid passes through."}, {"id": "sds72003", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Separating Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which separating technique would best separate dissolved salt from water?", "options": ["filtration", "evaporation", "magnetism", "sieving"], "answer": 1, "exp": "Evaporation removes the water by turning it into vapour, leaving the dissolved salt behind as a solid.", "hint": "Since the salt is dissolved, filtration won't work — think about removing the water itself instead."}, {"id": "sds72004", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Separating Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which separating technique would best separate iron filings from sand?", "options": ["filtration", "evaporation", "magnetism", "distillation"], "answer": 2, "exp": "Magnetism can be used to attract and remove iron filings, since iron is magnetic and sand is not.", "hint": "Think about a property that iron has, but sand does not."}, {"id": "sds72005", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Particle Theory", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "In the particle model, which state of matter has particles that are tightly packed and vibrate in fixed positions?", "options": ["solid", "liquid", "gas", "plasma"], "answer": 0, "exp": "In a solid, particles are tightly packed in a fixed arrangement and can only vibrate in place, unlike liquids and gases.", "hint": "This state of matter holds its shape because its particles can't move past each other."}, {"id": "sds72006", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Particle Theory", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "In the particle model, which state of matter has particles that move freely and are spread far apart?", "options": ["solid", "liquid", "gas", "none of these"], "answer": 2, "exp": "In a gas, particles move freely and rapidly, spread far apart from one another, allowing gases to expand to fill their container.", "hint": "This state of matter can expand to fill any container, because its particles are so spread out."}, {"id": "sds72007", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Particle Theory", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "What happens to the particles in a substance as it changes from a solid to a liquid (melting)?", "options": ["the particles disappear", "the particles gain energy and move further apart, but stay relatively close", "the particles stop moving entirely", "the particles turn into a different substance"], "answer": 1, "exp": "As a solid melts, its particles gain energy, move faster, and spread slightly further apart, though they remain relatively close compared to a gas.", "hint": "Think about particles gaining enough energy to move past each other, but not flying far apart."}, {"id": "sds72008", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Mixtures — Solutions", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "A solution is made by dissolving sugar in water. Which substance is the solute?", "options": ["water", "sugar", "the solution itself", "none of these"], "answer": 1, "exp": "The solute is the substance being dissolved — in this case, the sugar. The water is the solvent, doing the dissolving.", "hint": "The solute is the substance that disappears into the liquid as it dissolves."}, {"id": "sds72009", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Mixtures — Solutions", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "A solution is made by dissolving sugar in water. Which substance is the solvent?", "options": ["sugar", "water", "the mixture", "carbon dioxide"], "answer": 1, "exp": "The solvent is the substance doing the dissolving — in this case, the water.", "hint": "The solvent is the liquid that the other substance dissolves into."}, {"id": "sds72010", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which of these mixtures is a 'suspension', where particles eventually settle if left undisturbed?", "options": ["salt water", "muddy water", "oxygen and nitrogen gas mixed together", "sugar dissolved in tea"], "answer": 1, "exp": "Muddy water is a suspension, since the solid particles are not fully dissolved and will eventually settle to the bottom if left undisturbed.", "hint": "Think about a mixture where you can see solid particles that will eventually sink."}, {"id": "sds72011", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Density", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "A metal block has a mass of 200 g and a volume of 50 mL. What is its density?", "options": ["2 g/mL", "4 g/mL", "10 g/mL", "50 g/mL"], "answer": 1, "exp": "Step 1: Density = mass ÷ volume. Step 2: 200 ÷ 50 = 4 g/mL.", "hint": "Divide the mass by the volume."}, {"id": "sds72012", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Mixtures — Concentration", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "30 g of salt is fully dissolved in 270 g of water. What percentage of the total mixture is salt?", "options": ["3%", "10%", "11%", "30%"], "answer": 1, "exp": "Step 1: Total mass = 30 + 270 = 300 g. Step 2: Percentage = (30 ÷ 300) × 100 = 10%.", "hint": "Divide the mass of salt by the total mass of the mixture, then convert to a percentage."}, {"id": "sds72013", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Particle Theory — Changes of State", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which process changes a gas directly into a liquid?", "options": ["evaporation", "condensation", "sublimation", "melting"], "answer": 1, "exp": "Condensation is the process of a gas changing into a liquid, such as water vapour turning into liquid water droplets.", "hint": "Think about what happens to water vapour when it touches a cold surface, like a cold glass."}, {"id": "sds72014", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Particle Theory — Changes of State", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which process changes a solid directly into a gas, without passing through a liquid state?", "options": ["evaporation", "condensation", "sublimation", "freezing"], "answer": 2, "exp": "Sublimation is the process of a solid changing directly into a gas, without becoming a liquid first, such as dry ice (solid carbon dioxide) turning into gas.", "hint": "Think about dry ice — it 'disappears' into a gas without ever becoming a visible puddle."}, {"id": "sds72015", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Separating Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Distillation is most useful for separating which type of mixture?", "options": ["a mixture of two liquids with different boiling points", "a mixture of two solids with the same colour", "a mixture of magnetic and non-magnetic solids", "a mixture of gases with the same density"], "answer": 0, "exp": "Distillation separates liquids with different boiling points, by heating the mixture so one liquid evaporates first, then cooling and collecting it separately.", "hint": "This technique relies on liquids evaporating at different temperatures."}, {"id": "sds72016", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which of these best describes a 'pure substance'?", "options": ["a substance made of only one type of particle (element or compound)", "a substance that is always a liquid", "a substance with no colour", "a substance found only in nature"], "answer": 0, "exp": "A pure substance is made up of only one type of particle, whether that's a single element or a single compound, with nothing else mixed in.", "hint": "Think about the difference between something with multiple ingredients and something with only one."}, {"id": "sds72017", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Particle Theory", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Why do gases expand to fill any container they are placed in, according to the particle model?", "options": ["their particles are tightly packed", "their particles move quickly and spread out in all directions, with weak attraction between them", "they have no particles at all", "they are always heavier than liquids"], "answer": 1, "exp": "Gas particles move quickly in all directions and have very weak attraction between them, allowing them to spread out and fill any available space.", "hint": "Think about how freely and quickly gas particles can move compared to particles in a liquid or solid."}, {"id": "sds72018", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Separating Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "A mixture of iron filings, sand, and salt needs to be fully separated. Which is the most logical first step?", "options": ["use a magnet to remove the iron filings", "add water immediately to dissolve everything", "heat the entire mixture", "filter the mixture through paper"], "answer": 0, "exp": "Using a magnet first cleanly removes the iron filings without disturbing the sand or salt, making it the most logical first step before further separating the remaining sand and salt.", "hint": "Start with the separation method that can remove one component without affecting the others."}, {"id": "sds72019", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Particle Theory", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "What is the term for the smallest particle of an element that retains the properties of that element?", "options": ["a molecule", "an atom", "a compound", "a mixture"], "answer": 1, "exp": "An atom is the smallest particle of an element that still retains the properties of that element.", "hint": "This is the basic building block of all matter, smaller than a molecule of a compound."}, {"id": "sds72020", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Particle Theory", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which of these is an example of a compound?", "options": ["oxygen gas (O₂)", "water (H₂O)", "salt water", "air"], "answer": 1, "exp": "Water (H₂O) is a compound, formed when hydrogen and oxygen atoms chemically bond together in a fixed ratio.", "hint": "A compound is formed from two or more different elements chemically bonded together."}, {"id": "sds72021", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Separating Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Sieving is most useful for separating mixtures of which type?", "options": ["two liquids", "two gases", "solid particles of different sizes", "two substances with the same particle size"], "answer": 2, "exp": "Sieving separates solid particles of different sizes, allowing smaller particles to pass through the holes of the sieve while larger particles are caught.", "hint": "Think about a kitchen sieve used to separate larger lumps from finer powder."}, {"id": "sds72022", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Particle Theory — Changes of State", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "As particles in a substance lose energy and slow down, which change of state is most likely occurring?", "options": ["melting", "freezing", "evaporating", "boiling"], "answer": 1, "exp": "As particles lose energy and slow down, they move closer together and can form a more ordered, fixed structure — this describes freezing (liquid to solid).", "hint": "Think about a liquid losing energy as it cools, eventually forming a solid."}, {"id": "sds72023", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Separating Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which two properties are most useful for deciding which separating technique to use for a mixture?", "options": ["colour and smell", "the states of matter and particle sizes/properties involved", "the temperature of the room", "the cost of the equipment"], "answer": 1, "exp": "The choice of separating technique depends on the states of matter involved (solid, liquid, gas) and specific particle properties, such as size, magnetism, or boiling point.", "hint": "Think about what scientific properties (not just appearance) actually determine which method will work."}, {"id": "sds72024", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Mixtures — Solutions", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "Which best explains why salt dissolves in water but sand does not?", "options": ["salt particles separate and spread evenly among water particles, while sand particles do not break apart this way", "sand is too heavy to ever mix with water", "salt is a liquid, but sand is a solid", "water cannot interact with any solid at all"], "answer": 0, "exp": "Salt particles separate from each other and spread evenly throughout the water (dissolving), while sand particles remain intact and simply settle, since they do not interact with water in the same way.", "hint": "Think about what actually happens to the tiny particles of salt once they're added to water, compared to sand."}, {"id": "sds72025", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Separating Mixtures", "difficulty": "medium", "style": "standard", "paper": "G7-S2", "q": "A scientist heats a mixture of salt water until all the water evaporates. What remains in the container?", "options": ["nothing at all", "pure water", "solid salt crystals", "a new gas"], "answer": 2, "exp": "As the water evaporates, the dissolved salt is left behind, forming solid salt crystals in the container.", "hint": "Think about what happens to the salt once the water that was dissolving it is gone."}, {"id": "sds73001", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "What is a force?", "options": ["a push or a pull acting on an object", "a type of energy only", "a measurement of mass", "a type of chemical reaction"], "answer": 0, "exp": "A force is any push or pull that acts on an object, which can cause it to start, stop, speed up, slow down, or change direction.", "hint": "Think about the simplest possible action you can do to an object — pushing or pulling it."}, {"id": "sds73002", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "What happens to an object when balanced forces act on it?", "options": ["it always speeds up", "it always slows down", "its motion does not change (it stays still or continues at constant speed)", "it changes direction randomly"], "answer": 2, "exp": "When forces acting on an object are balanced (equal and opposite), the object's motion does not change — it remains still, or continues moving at a constant speed in a straight line.", "hint": "Think about what happens when two equal forces push against each other with no net effect."}, {"id": "sds73003", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces — Friction", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "What is friction?", "options": ["a force that speeds up moving objects", "a force that opposes motion between two surfaces in contact", "a type of energy stored in objects", "a force that only exists in water"], "answer": 1, "exp": "Friction is a force that opposes (resists) motion between two surfaces in contact, often converting some kinetic energy into heat.", "hint": "Think about the force that makes it harder to slide an object across a rough surface."}, {"id": "sds73004", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces — Friction", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which surface would create the LEAST friction for an object sliding across it?", "options": ["rough concrete", "ice", "sandpaper", "carpet"], "answer": 1, "exp": "Ice is a very smooth surface, creating much less friction than rough materials like concrete, sandpaper, or carpet.", "hint": "Think about which surface is smoothest, since smoother surfaces generally create less friction."}, {"id": "sds73005", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces — Gravity", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these is an example of gravitational force?", "options": ["a magnet attracting a paperclip", "a ball falling to the ground after being thrown upward", "a balloon rubbed on hair becoming charged", "water boiling in a kettle"], "answer": 1, "exp": "Gravity is the force pulling objects toward the Earth, causing a thrown ball to eventually fall back down.", "hint": "Think about the force that pulls everything on Earth downward."}, {"id": "sds73006", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Simple Machines", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "A lever has a load of 100 N and requires an effort force of 25 N to lift it. What is the mechanical advantage of this lever?", "options": ["2", "4", "25", "100"], "answer": 1, "exp": "Step 1: Mechanical advantage = load force ÷ effort force. Step 2: 100 ÷ 25 = 4.", "hint": "Divide the load force by the effort force."}, {"id": "sds73007", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Energy", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these correctly describes kinetic energy?", "options": ["energy stored due to position", "the energy of motion", "energy released during chemical reactions only", "energy associated with electric charge"], "answer": 1, "exp": "Kinetic energy is the energy an object has due to its motion — the faster something moves, the more kinetic energy it has.", "hint": "This type of energy depends specifically on whether something is moving."}, {"id": "sds73008", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Energy", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these correctly describes gravitational potential energy?", "options": ["energy stored in a stretched rubber band", "energy stored due to an object's height above the ground", "the energy of a moving object", "energy released as heat"], "answer": 1, "exp": "Gravitational potential energy is stored energy due to an object's height above the ground — the higher the object, the more potential energy it has.", "hint": "Think about the energy an object has simply because of how high up it is."}, {"id": "sds73009", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Energy — Transformations", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "A ball is held still at the top of a hill, then released to roll down. What energy transformation occurs?", "options": ["kinetic energy transforms into gravitational potential energy", "gravitational potential energy transforms into kinetic energy", "chemical energy transforms into light energy", "sound energy transforms into heat energy"], "answer": 1, "exp": "As the ball rolls down, its stored gravitational potential energy (due to height) is transformed into kinetic energy (motion).", "hint": "Think about what happens to the ball's height-based energy as it starts moving."}, {"id": "sds73010", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Simple Machines", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which simple machine is a doorstop wedged under a door an example of?", "options": ["a lever", "a wedge", "a pulley", "a wheel and axle"], "answer": 1, "exp": "A wedge is a simple machine shaped to apply force over a small area, such as a doorstop holding a door in place.", "hint": "Think about the shape of this object — thin and angled, used to hold something in place."}, {"id": "sds73011", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces and Energy", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Work is done on an object when a force of 50 N moves it 4 metres. How much work is done?", "options": ["12.5 J", "46 J", "54 J", "200 J"], "answer": 3, "exp": "Step 1: Work done = force × distance. Step 2: 50 × 4 = 200 J (joules).", "hint": "Multiply the force applied by the distance the object moves."}, {"id": "sds73012", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces and Motion", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "A car travels 100 metres in 20 seconds. What is its average speed?", "options": ["2 m/s", "5 m/s", "20 m/s", "2000 m/s"], "answer": 1, "exp": "Step 1: Speed = distance ÷ time. Step 2: 100 ÷ 20 = 5 m/s.", "hint": "Divide the distance travelled by the time taken."}, {"id": "sds73013", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Energy", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these is an example of elastic potential energy?", "options": ["a stretched bow about to fire an arrow", "sunlight shining on a solar panel", "a car moving at high speed", "heat from a campfire"], "answer": 0, "exp": "A stretched bow stores elastic potential energy due to its deformation, which is released as kinetic energy when the arrow is fired.", "hint": "Think about an object that has been stretched or compressed, ready to spring back."}, {"id": "sds73014", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces — Newton's Laws", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these correctly describes Newton's first law of motion (the law of inertia)?", "options": ["objects always speed up over time", "an object at rest stays at rest, and an object in motion stays in motion, unless acted on by an unbalanced force", "force equals mass multiplied by acceleration", "every action has an equal and opposite reaction"], "answer": 1, "exp": "Newton's first law states that an object's motion will not change unless an unbalanced force acts on it — objects naturally resist changes to their motion (inertia).", "hint": "Think about what keeps an object doing what it's already doing, unless something interferes."}, {"id": "sds73015", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces — Newton's Laws", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these correctly describes Newton's third law of motion?", "options": ["objects at rest tend to stay at rest", "for every action force, there is an equal and opposite reaction force", "force equals mass times acceleration", "heavier objects always fall faster"], "answer": 1, "exp": "Newton's third law states that for every action force, there is an equal and opposite reaction force, such as a swimmer pushing water backward to move forward.", "hint": "Think about paired forces — one action, and an equal but opposite reaction."}, {"id": "sds73016", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces — Friction", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these would reduce friction between two moving surfaces?", "options": ["adding sand between them", "adding oil or lubricant between them", "pressing them together more tightly", "roughening both surfaces"], "answer": 1, "exp": "Adding oil or lubricant reduces friction by allowing surfaces to slide more smoothly past each other.", "hint": "Think about why mechanics add a slippery substance to moving machine parts."}, {"id": "sds73017", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Simple Machines", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "A pulley system is used to lift a heavy box. What is the main advantage of using a pulley?", "options": ["it makes the box lighter", "it changes the direction of the force needed and can reduce the effort required", "it eliminates the need for any force at all", "it only works on liquids"], "answer": 1, "exp": "A pulley can change the direction of an applied force (for example, allowing you to pull down instead of lift up) and, with multiple pulleys, can reduce the effort force needed.", "hint": "Think about how a pulley changes the direction you need to apply force, and how it can make lifting easier."}, {"id": "sds73018", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Energy", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which form of energy is sound?", "options": ["energy caused by vibrations travelling through a medium", "energy caused only by electricity", "energy stored in chemical bonds", "energy associated with light"], "answer": 0, "exp": "Sound energy is produced by vibrations that travel through a medium (like air, water, or solids) as waves.", "hint": "Think about what's actually moving through the air when you hear a sound."}, {"id": "sds73019", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces — Friction", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "A toy car rolls down a ramp and across a flat, rough carpet, eventually stopping. What force mainly causes it to slow down and stop on the carpet?", "options": ["gravity", "friction", "magnetism", "elastic force"], "answer": 1, "exp": "Friction between the toy car's wheels and the rough carpet surface gradually slows the car down until it stops.", "hint": "Think about the resistive force acting between the car's wheels and the carpet."}, {"id": "sds73020", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces — Units", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these is the correct unit for measuring force?", "options": ["joule", "newton", "watt", "metre"], "answer": 1, "exp": "Force is measured in newtons (N), named after Sir Isaac Newton.", "hint": "This unit shares its name with a famous scientist known for his laws of motion."}, {"id": "sds73021", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Energy — Units", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these is the correct unit for measuring energy?", "options": ["newton", "joule", "metre", "second"], "answer": 1, "exp": "Energy is measured in joules (J).", "hint": "This unit is also used to measure work done, since work and energy are closely related."}, {"id": "sds73022", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Energy — Transformations", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "A spring is compressed and then released, launching a small toy into the air. Which energy transformation best describes this?", "options": ["elastic potential energy transforms into kinetic energy", "kinetic energy transforms into chemical energy", "sound energy transforms into light energy", "gravitational potential energy transforms into elastic energy"], "answer": 0, "exp": "The compressed spring stores elastic potential energy, which transforms into kinetic energy as it releases and launches the toy.", "hint": "Think about the energy stored in the compressed spring, just before it's released."}, {"id": "sds73023", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these scenarios shows an UNBALANCED force acting on an object?", "options": ["a parked car with its brakes on", "a book resting motionlessly on a table", "a ball accelerating as it rolls down a hill", "a tug-of-war where both teams pull with exactly equal force"], "answer": 2, "exp": "A ball accelerating down a hill shows an unbalanced force (gravity pulling it down the slope is greater than any resisting force), causing a change in its motion.", "hint": "Look for the scenario where an object's speed is actually changing."}, {"id": "sds73024", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Forces — Newton's Laws", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "Which of these best explains why wearing a seatbelt helps protect you in a sudden stop?", "options": ["it increases your speed", "it helps apply a force to slow your body down with the car, rather than continuing forward due to inertia", "it eliminates all forces acting on your body", "it has no real safety function"], "answer": 1, "exp": "Due to inertia, your body tends to keep moving forward even when the car suddenly stops. A seatbelt applies a force to slow your body down along with the car, preventing you from continuing forward.", "hint": "Think about Newton's first law — your body 'wants' to keep moving even when the car stops suddenly."}, {"id": "sds73025", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Simple Machines", "difficulty": "medium", "style": "standard", "paper": "G7-S3", "q": "A wheelbarrow lifts a 120 N load using an effort of only 30 N, due to its lever action. What is the mechanical advantage?", "options": ["2", "3", "4", "30"], "answer": 2, "exp": "Step 1: Mechanical advantage = load force ÷ effort force. Step 2: 120 ÷ 30 = 4.", "hint": "Divide the load force by the effort force."}, {"id": "sds74001", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Earth and Space", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "What causes day and night on Earth?", "options": ["the Earth's revolution around the Sun", "the Earth's rotation on its own axis", "the Moon blocking the Sun", "the Sun moving around the Earth"], "answer": 1, "exp": "Earth's rotation on its own axis, completed roughly every 24 hours, causes different parts of Earth to face toward or away from the Sun, creating day and night.", "hint": "Think about the Earth spinning, not about the Sun or Moon physically moving around it."}, {"id": "sds74002", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Earth and Space", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "What causes the four seasons on Earth?", "options": ["the changing distance between Earth and the Sun throughout the year", "the tilt of Earth's axis as it orbits the Sun", "the Moon's phases", "random weather patterns"], "answer": 1, "exp": "Earth's axis is tilted, so different parts of Earth receive more or less direct sunlight at different points in its orbit, causing the seasons.", "hint": "Think about the angle of Earth's axis, not its distance from the Sun."}, {"id": "sds74003", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Earth and Space", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "How long does it take Earth to complete one full orbit around the Sun?", "options": ["24 hours", "one month", "one year", "ten years"], "answer": 2, "exp": "Earth takes approximately one year (365.25 days) to complete one full orbit around the Sun.", "hint": "Think about how long it takes for the seasons to repeat in the same order."}, {"id": "sds74004", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Earth and Space", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "Which of these correctly orders the planets from closest to the Sun?", "options": ["Mercury, Venus, Earth, Mars", "Venus, Mercury, Earth, Mars", "Earth, Venus, Mercury, Mars", "Mars, Earth, Venus, Mercury"], "answer": 0, "exp": "The correct order of the four innermost planets, from closest to the Sun, is: Mercury, Venus, Earth, Mars.", "hint": "Mercury, being smallest and closest, comes first; Mars, the red planet, comes last in this list."}, {"id": "sds74005", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Earth and Space", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "What causes the Moon's phases (such as full moon and new moon)?", "options": ["the Moon changing shape", "the changing amount of sunlit Moon visible from Earth as it orbits", "clouds blocking parts of the Moon", "the Moon spinning very quickly"], "answer": 1, "exp": "The Moon's phases are caused by the changing amount of its sunlit half that is visible from Earth, as the Moon orbits around us.", "hint": "Think about how much of the sunlit side of the Moon you can actually see from Earth at different times."}, {"id": "sds74006", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Earth Science", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "Which layer of the Earth is the outermost, solid layer that we live on?", "options": ["the core", "the mantle", "the crust", "the atmosphere"], "answer": 2, "exp": "The crust is the thin, outermost solid layer of the Earth, on which we live.", "hint": "This is the thinnest of Earth's main layers, forming the surface we walk on."}, {"id": "sds74007", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Earth Science", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "Which layer of the Earth is mostly liquid metal and generates Earth's magnetic field?", "options": ["the crust", "the mantle", "the outer core", "the inner core"], "answer": 2, "exp": "The outer core is made of liquid metal (mostly iron and nickel), and its movement generates Earth's magnetic field.", "hint": "This liquid layer's movement is responsible for Earth acting like a giant magnet."}, {"id": "sds74008", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Ecosystems", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "In an ecosystem, what is the term for all the living things of one species in a particular area?", "options": ["a community", "a population", "a habitat", "a biome"], "answer": 1, "exp": "A population refers to all the living things of one species within a particular area, such as all the rabbits in a field.", "hint": "This term refers to organisms of just ONE species, not all species together."}, {"id": "sds74009", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Ecosystems", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "In an ecosystem, what is the term for all the different populations of different species living and interacting in one area?", "options": ["a community", "a population", "an organism", "an individual"], "answer": 0, "exp": "A community refers to all the different populations of different species living and interacting together within an area.", "hint": "This term includes multiple different species interacting together, not just one."}, {"id": "sds74010", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Scientific Method", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "A student wants to test whether plant growth is affected by the amount of water given. What should be the ONLY variable changed between the test groups?", "options": ["the type of plant pot used", "the amount of water given", "the location of the experiment", "the time of day measurements are taken"], "answer": 1, "exp": "To fairly test the effect of water on plant growth, only the amount of water should be changed between groups, while everything else (pot, location, soil, etc.) is kept the same.", "hint": "Look for the variable that directly matches what the student is trying to test."}, {"id": "sds74011", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Scientific Method", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "In a scientific experiment, what is a 'controlled variable'?", "options": ["the variable being changed deliberately", "a variable that is kept the same throughout the experiment to ensure a fair test", "the result of the experiment", "a variable that changes randomly"], "answer": 1, "exp": "A controlled variable is kept the same throughout an experiment, ensuring that any change in results can be attributed to the variable being tested, not something else.", "hint": "This type of variable is deliberately kept constant, not changed."}, {"id": "sds74012", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Scientific Method", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "What is a hypothesis in a scientific investigation?", "options": ["a proven fact", "a testable prediction based on existing knowledge", "the final conclusion of an experiment", "a type of measuring tool"], "answer": 1, "exp": "A hypothesis is a testable prediction, based on existing knowledge, that an experiment is designed to test.", "hint": "This is made BEFORE the experiment, as an educated guess that can be tested."}, {"id": "sds74013", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Scientific Method", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "Why is it important to repeat an experiment multiple times?", "options": ["to use up extra materials", "to increase reliability and reduce the effect of errors or unusual results", "to make the experiment take longer", "repeating experiments is never necessary"], "answer": 1, "exp": "Repeating an experiment increases the reliability of results, helping to identify and reduce the effect of errors or unusual one-off results (anomalies).", "hint": "Think about how repeating something helps you trust the results more."}, {"id": "sds74014", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Ecosystems", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "In a community, what role do decomposers play?", "options": ["they produce their own food using sunlight", "they break down dead organisms and waste, recycling nutrients", "they hunt other animals for food", "they have no real role in the ecosystem"], "answer": 1, "exp": "Decomposers break down dead organisms and waste material, recycling important nutrients back into the ecosystem for other organisms to use.", "hint": "Think about what happens to a fallen leaf or a dead animal over time."}, {"id": "sds74015", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Scientific Method", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "What is an 'independent variable' in a scientific experiment?", "options": ["the variable that is deliberately changed by the experimenter", "the variable that is measured as a result", "a variable kept constant throughout", "the equipment used in the experiment"], "answer": 0, "exp": "The independent variable is the one variable deliberately changed by the experimenter to observe its effect.", "hint": "This is the variable the experimenter has direct control over and changes on purpose."}, {"id": "sds74016", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Scientific Method", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "What is a 'dependent variable' in a scientific experiment?", "options": ["the variable that is deliberately changed", "the variable that is measured, which may change as a result of the independent variable", "a variable kept constant throughout", "the hypothesis itself"], "answer": 1, "exp": "The dependent variable is what is measured during the experiment, since it may change depending on (be 'dependent' on) the independent variable.", "hint": "This variable's value 'depends on' what happens to the independent variable."}, {"id": "sds74017", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Earth Science", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "Which best describes the relative size and proportion of Earth's layers, from largest to smallest in thickness?", "options": ["crust, mantle, core", "mantle, crust, core", "mantle, core, crust", "core, mantle, crust"], "answer": 1, "exp": "The mantle is by far the thickest layer, followed by the crust (thinner still), with the core making up Earth's centre.", "hint": "The mantle makes up the largest portion of Earth's total volume."}, {"id": "sds74018", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Ecosystems", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "What is an 'ecosystem'?", "options": ["a single species living alone", "all the living and non-living things interacting together in an area", "only the non-living parts of an environment", "a type of classification key"], "answer": 1, "exp": "An ecosystem includes all the living things (plants, animals, fungi, bacteria) and non-living things (water, soil, climate) interacting together within an area.", "hint": "This term includes BOTH living and non-living parts of an environment, working together."}, {"id": "sds74019", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Scientific Method", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "Why do scientists use a control group in many experiments?", "options": ["to provide a baseline for comparison against the test group", "to make the experiment take less time", "to use fewer resources", "control groups are never necessary"], "answer": 0, "exp": "A control group provides a baseline for comparison, helping scientists see the actual effect of the variable being tested in the experimental group.", "hint": "Think about needing something to compare your results against, to know if the variable really made a difference."}, {"id": "sds74020", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Scientific Method", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "A student's experiment about plant growth lacks a clear, written method, making it impossible for another student to repeat. Why is this a problem?", "options": ["repeatability is not actually important in science", "without a clear method, it's hard for others to verify or trust the results", "the student will automatically fail", "this is not a problem at all"], "answer": 1, "exp": "A clear, written method allows other scientists to repeat the experiment and verify whether the results are reliable — without it, the findings are much harder to trust or confirm.", "hint": "Think about why other scientists need to know exactly what was done, in order to check the results."}, {"id": "sds74021", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Earth Science", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "Which best describes the difference between weathering and erosion?", "options": ["weathering breaks down rock in place, while erosion moves the broken material elsewhere", "erosion only happens underwater", "weathering and erosion mean exactly the same thing", "weathering only happens to living things"], "answer": 0, "exp": "Weathering breaks down rocks and minerals in place (without movement), while erosion involves moving the broken material to a new location, often by wind or water.", "hint": "Think about the difference between something breaking apart and something being carried away."}, {"id": "sds74022", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Earth and Space", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "What is the main source of energy that drives weather patterns on Earth?", "options": ["the Moon", "the Sun", "Earth's core", "ocean currents alone"], "answer": 1, "exp": "The Sun's energy heats Earth's surface unevenly, driving the air movements, evaporation, and temperature differences that create weather patterns.", "hint": "Think about the ultimate energy source that warms our atmosphere and oceans."}, {"id": "sds74023", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Scientific Method", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "A scientist tests a new fertiliser on tomato plants, using one group with fertiliser and one group without, while keeping water, sunlight and soil the same. What is the purpose of keeping water, sunlight and soil the same?", "options": ["to ensure a fair test, isolating the fertiliser as the only variable affecting growth", "to make the experiment cheaper", "it serves no real purpose", "to make the experiment take longer to complete"], "answer": 0, "exp": "Keeping all other variables the same ensures a fair test, so any difference in plant growth can be attributed specifically to the fertiliser, not some other factor.", "hint": "Think about why only ONE thing should be different between the two groups being compared."}, {"id": "sds74024", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Ecosystems", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "Which best describes a 'biome'?", "options": ["a single ecosystem found only in one specific location", "a large natural area characterised by its climate, plants and animals, such as a desert or rainforest", "a type of rock formation", "a unit used to measure temperature"], "answer": 1, "exp": "A biome is a large natural region characterised by its climate and the types of plants and animals adapted to live there, such as deserts, rainforests, or grasslands.", "hint": "Think about large-scale natural regions, like deserts or rainforests, found in many parts of the world."}, {"id": "sds74025", "state": "AU", "section": "sec_science", "grade": "7", "topic": "Scientific Method", "difficulty": "medium", "style": "standard", "paper": "G7-S4", "q": "Why might a scientific claim be considered unreliable if it is based on only a single observation, with no repeated testing?", "options": ["single observations are always wrong", "without repetition, it's hard to rule out chance, error, or unusual one-off results", "scientific claims never need any testing at all", "this is actually the most reliable type of evidence"], "answer": 1, "exp": "A single observation could easily be the result of chance, error, or an unusual one-off occurrence, so repeated testing is needed to build confidence in a scientific claim.", "hint": "Think about why one single result might not give the full, reliable picture."}, {"id": "sds81001", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Digestive", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which organ in the digestive system is primarily responsible for absorbing most nutrients into the bloodstream?", "options": ["the stomach", "the small intestine", "the large intestine", "the oesophagus"], "answer": 1, "exp": "The small intestine has a large surface area (due to structures called villi) and is where most nutrient absorption into the bloodstream occurs.", "hint": "Think about the organ with the largest surface area for absorbing nutrients."}, {"id": "sds81002", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Digestive", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "What is the main function of the large intestine?", "options": ["to absorb most nutrients", "to absorb water and form solid waste", "to digest proteins using acid", "to pump blood around the body"], "answer": 1, "exp": "The large intestine mainly absorbs water from undigested food, forming more solid waste before it leaves the body.", "hint": "Think about what happens to the leftover material after most nutrients have already been absorbed."}, {"id": "sds81003", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Respiratory", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which structures in the lungs are responsible for gas exchange (oxygen and carbon dioxide)?", "options": ["bronchi", "trachea", "alveoli", "diaphragm"], "answer": 2, "exp": "Alveoli are tiny air sacs in the lungs with thin walls and a large surface area, allowing efficient gas exchange between air and blood.", "hint": "Think about the smallest structures in the lungs, where the actual exchange of gases happens."}, {"id": "sds81004", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Respiratory", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "What is the role of the diaphragm in breathing?", "options": ["it filters air before it reaches the lungs", "it contracts and relaxes to change the volume of the chest cavity, drawing air in and pushing it out", "it produces red blood cells", "it warms the air before breathing"], "answer": 1, "exp": "The diaphragm is a muscle that contracts (flattens) to draw air into the lungs, and relaxes (domes upward) to help push air back out.", "hint": "Think about the muscle that changes the size of your chest cavity as you breathe."}, {"id": "sds81005", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Circulatory", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which blood vessels carry oxygen-rich blood away from the heart to the rest of the body?", "options": ["veins", "arteries", "capillaries", "valves"], "answer": 1, "exp": "Arteries carry oxygen-rich blood away from the heart to the rest of the body (with the exception of the pulmonary artery).", "hint": "Remember: arteries generally carry blood away from the heart."}, {"id": "sds81006", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Circulatory", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "What is the main function of red blood cells?", "options": ["to fight infection", "to carry oxygen around the body", "to help blood clot", "to digest food"], "answer": 1, "exp": "Red blood cells contain haemoglobin, which binds to oxygen and carries it from the lungs to the rest of the body.", "hint": "Think about the substance in these cells that gives blood its red colour and carries a vital gas."}, {"id": "sds81007", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Integration", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which best describes the relationship between the digestive, circulatory, and respiratory systems?", "options": ["they work completely independently with no connection", "digestion provides nutrients, the respiratory system provides oxygen, and the circulatory system transports both to body cells", "only the circulatory system matters for survival", "the respiratory system absorbs nutrients directly"], "answer": 1, "exp": "These systems work together: digestion breaks down food into nutrients, the respiratory system brings in oxygen, and the circulatory system transports both throughout the body to where they're needed.", "hint": "Think about how these three systems depend on each other to deliver what cells need to function."}, {"id": "sds81008", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Chemical Reactions", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which of these is a clear sign that a chemical reaction has occurred?", "options": ["a substance changes shape only", "a new substance forms with different properties, such as a colour change, gas production, or temperature change", "an object becomes heavier without explanation", "a liquid is poured into a container"], "answer": 1, "exp": "A chemical reaction is indicated by the formation of a new substance with different properties — shown through colour changes, gas bubbles, temperature changes, or light/sound production.", "hint": "Think about evidence that something NEW has actually formed, not just changed shape or container."}, {"id": "sds81009", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Chemical Reactions", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "In a chemical reaction, what are the 'reactants'?", "options": ["the substances that form as a result of the reaction", "the original substances that react together", "the energy released during the reaction", "the equipment used in the experiment"], "answer": 1, "exp": "Reactants are the original substances present at the start of a chemical reaction, before they react together to form products.", "hint": "Think about the substances you START with, before any reaction takes place."}, {"id": "sds81010", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Chemical Reactions", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "According to the law of conservation of mass, what happens to the total mass in a chemical reaction conducted in a sealed container?", "options": ["the mass always increases", "the mass always decreases", "the total mass remains the same before and after the reaction", "mass is destroyed completely"], "answer": 2, "exp": "The law of conservation of mass states that mass is neither created nor destroyed in a chemical reaction — the total mass of reactants equals the total mass of products, in a sealed system.", "hint": "Think about whether matter can simply disappear or appear during a reaction, if nothing is added or removed."}, {"id": "sds81011", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Chemical Reactions", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which of these is an example of an exothermic reaction (one that releases heat)?", "options": ["ice melting", "combustion (burning) of wood", "photosynthesis", "water evaporating"], "answer": 1, "exp": "Combustion releases heat energy as wood burns, making it an exothermic reaction. Melting, photosynthesis, and evaporation generally absorb energy (endothermic processes).", "hint": "Think about which of these processes clearly produces noticeable heat as it happens."}, {"id": "sds81012", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Chemical Reactions", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which of these is an example of an endothermic reaction (one that absorbs heat from its surroundings)?", "options": ["burning fuel for energy", "an instant cold pack reaction, which feels cold as it activates", "fireworks exploding", "a campfire burning"], "answer": 1, "exp": "An instant cold pack absorbs heat from its surroundings as its chemical reaction occurs, making it feel cold — a clear example of an endothermic reaction.", "hint": "Think about a reaction that makes its surroundings feel colder, rather than hotter."}, {"id": "sds81013", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Density", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "A metal block has a mass of 500 g and a volume of 62.5 mL. What is its density?", "options": ["6 g/mL", "7 g/mL", "8 g/mL", "9 g/mL"], "answer": 2, "exp": "Step 1: Density = mass ÷ volume. Step 2: 500 ÷ 62.5 = 8 g/mL.", "hint": "Divide the mass by the volume."}, {"id": "sds81014", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Respiratory", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which of these structures protects the lungs and other organs in the chest cavity?", "options": ["the ribcage", "the small intestine", "the large intestine", "the appendix"], "answer": 0, "exp": "The ribcage is a bony structure that surrounds and protects the lungs, heart, and other organs in the chest cavity.", "hint": "Think about the bony cage-like structure surrounding your chest."}, {"id": "sds81015", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Circulatory", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "What is the function of valves within the heart and veins?", "options": ["to produce new blood cells", "to prevent blood from flowing backward", "to filter waste from the blood", "to absorb oxygen directly"], "answer": 1, "exp": "Valves act like one-way doors, preventing blood from flowing backward and ensuring it moves in the correct direction through the heart and veins.", "hint": "Think about a structure that ensures blood keeps moving in only one direction."}, {"id": "sds81016", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Chemical Reactions", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which type of chemical reaction occurs when two or more substances combine to form a single new substance?", "options": ["a synthesis (combination) reaction", "a decomposition reaction", "a displacement reaction", "a precipitation reaction only"], "answer": 0, "exp": "A synthesis (or combination) reaction occurs when two or more reactants combine to form one single new product.", "hint": "Think about reactants joining TOGETHER to make one single new substance."}, {"id": "sds81017", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Chemical Reactions", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which type of chemical reaction occurs when a single substance breaks down into two or more simpler substances?", "options": ["a synthesis reaction", "a decomposition reaction", "a combustion reaction only", "none of these"], "answer": 1, "exp": "A decomposition reaction occurs when a single compound breaks down into two or more simpler substances.", "hint": "Think about ONE substance breaking APART into smaller pieces, the opposite of combining."}, {"id": "sds81018", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Integration", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Why is it important for athletes to breathe more rapidly during intense exercise?", "options": ["to cool down their blood", "to take in more oxygen for their muscles and remove carbon dioxide more quickly", "to slow their heart rate", "breathing rate has no real connection to exercise"], "answer": 1, "exp": "During intense exercise, muscles need more oxygen for energy production and produce more carbon dioxide as waste, requiring faster breathing to meet these increased demands.", "hint": "Think about what muscles need more of, and what waste product they produce more of, during exercise."}, {"id": "sds81019", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Digestive", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which of these correctly describes the digestive process occurring in the stomach?", "options": ["nutrients are fully absorbed here", "strong acid and enzymes break down food, especially proteins", "water is the main substance absorbed here", "the stomach mainly stores undigested fibre"], "answer": 1, "exp": "The stomach produces strong acid and digestive enzymes that begin breaking down food, particularly proteins, before it moves into the small intestine.", "hint": "Think about the harsh chemical environment in the stomach and what it's designed to break down."}, {"id": "sds81020", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Chemical Reactions", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "In a balanced chemical equation, what does the law of conservation of mass require regarding atoms?", "options": ["atoms can be created during the reaction", "atoms can be destroyed during the reaction", "the number of each type of atom must be the same on both sides of the equation", "atoms change into different elements during reactions"], "answer": 2, "exp": "A balanced chemical equation requires the same number of each type of atom on both the reactant and product sides, since atoms are neither created nor destroyed in a chemical reaction.", "hint": "Think about why a chemical equation needs to be 'balanced' — what exactly needs to match on both sides?"}, {"id": "sds81021", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Digestive", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which best explains why enzymes are important in digestion?", "options": ["they slow down digestion to allow more time for absorption", "they speed up the breakdown of food molecules into smaller, absorbable pieces", "they have no real role in digestion", "they only work in the large intestine"], "answer": 1, "exp": "Enzymes act as biological catalysts, speeding up the chemical breakdown of food molecules into smaller pieces that can be absorbed by the body.", "hint": "Think about the role of a catalyst — something that speeds up a chemical process."}, {"id": "sds81022", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Chemical Reactions", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which of these would most likely indicate that a gas has been produced during a reaction in a test tube?", "options": ["the liquid becomes completely still", "bubbles or fizzing appear in the liquid", "the liquid changes container shape", "the test tube becomes heavier with no other change"], "answer": 1, "exp": "Bubbles or fizzing in a liquid is a common visible sign that a gas is being produced during a chemical reaction.", "hint": "Think about the visible sign you'd notice if a gas were escaping from a liquid."}, {"id": "sds81023", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Circulatory", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which structure pumps blood throughout the human body?", "options": ["the lungs", "the heart", "the liver", "the kidneys"], "answer": 1, "exp": "The heart is a muscular organ that pumps blood throughout the body via the circulatory system.", "hint": "Think about the organ whose rhythmic beating you can feel in your chest."}, {"id": "sds81024", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Chemical Reactions", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "A reaction between vinegar and baking soda produces carbon dioxide gas, water, and sodium acetate. If you weighed all the reactants and all the products in a sealed container, what would you expect to find?", "options": ["the products would weigh more than the reactants", "the products would weigh less than the reactants", "the total mass of reactants and products would be equal", "mass cannot be measured in chemical reactions"], "answer": 2, "exp": "According to the law of conservation of mass, the total mass remains the same in a sealed system — the reactants' mass equals the products' mass.", "hint": "Apply the law of conservation of mass to this sealed reaction."}, {"id": "sds81025", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Body Systems — Circulatory", "difficulty": "hard", "style": "standard", "paper": "G8-S1", "q": "Which best describes the overall pathway of blood flow through the body, starting from the heart?", "options": ["heart → lungs (pick up oxygen) → heart → body (deliver oxygen) → heart", "heart → body → lungs → heart only", "blood flows randomly with no clear pathway", "heart → kidneys → lungs → heart"], "answer": 0, "exp": "Blood flows from the heart to the lungs to pick up oxygen, returns to the heart, and is then pumped to the rest of the body to deliver that oxygen, before returning to the heart again.", "hint": "Think about the two main 'loops' blood travels: one to the lungs, and one to the rest of the body."}, {"id": "sds82001", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Particle Theory", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "According to the particle model, what happens to the kinetic energy of particles as temperature increases?", "options": ["it decreases", "it stays exactly the same", "it increases, causing particles to move faster", "kinetic energy is unrelated to temperature"], "answer": 2, "exp": "As temperature increases, particles gain kinetic energy and move faster, which is why substances often expand and change state as they're heated.", "hint": "Think about what happens to particle speed as something gets hotter."}, {"id": "sds82002", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which method of heat transfer occurs through direct contact between particles, such as a metal spoon heating up in hot soup?", "options": ["conduction", "convection", "radiation", "evaporation"], "answer": 0, "exp": "Conduction is heat transfer through direct contact between particles, passing energy from particle to particle without the particles themselves moving far.", "hint": "Think about heat moving through a solid material that the heat source is directly touching."}, {"id": "sds82003", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which method of heat transfer occurs through the movement of heated fluid (liquid or gas), such as warm air rising?", "options": ["conduction", "convection", "radiation", "none of these"], "answer": 1, "exp": "Convection is heat transfer through the movement of a fluid (liquid or gas), as warmer, less dense regions rise and cooler, denser regions sink.", "hint": "Think about heat being carried along by a moving fluid, like rising warm air."}, {"id": "sds82004", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which method of heat transfer does NOT require any particles or medium at all, allowing heat to travel through the vacuum of space?", "options": ["conduction", "convection", "radiation", "evaporation"], "answer": 2, "exp": "Radiation transfers heat as electromagnetic waves, which can travel through the vacuum of space without needing any particles or medium — this is how the Sun's heat reaches Earth.", "hint": "Think about how the Sun's heat reaches Earth, despite the empty vacuum of space in between."}, {"id": "sds82005", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Why do metals generally conduct heat better than materials like wood or plastic?", "options": ["metals are always colder to begin with", "metal particles are arranged in a way that transfers kinetic energy between particles very efficiently", "metals have no particles at all", "wood and plastic actively block all heat"], "answer": 1, "exp": "Metals have tightly packed particles (and free-moving electrons) that allow kinetic energy to transfer very efficiently between particles, making them good heat conductors.", "hint": "Think about how closely packed and well-connected metal particles are, compared to wood or plastic."}, {"id": "sds82006", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Electricity", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which best describes an electrical insulator?", "options": ["a material that allows electric current to flow easily", "a material that strongly resists the flow of electric current", "a material that only works underwater", "a material that generates its own electricity"], "answer": 1, "exp": "An electrical insulator strongly resists the flow of electric current, unlike a conductor which allows current to flow easily.", "hint": "Think about the opposite of a conductor — a material that blocks the flow of electricity."}, {"id": "sds82007", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Electricity", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "In a simple series circuit, what happens to the current if more resistors (like globes) are added?", "options": ["current increases", "current decreases", "current stays exactly the same regardless of resistance", "current becomes impossible to measure"], "answer": 1, "exp": "Adding more resistors in a series circuit increases the total resistance, which decreases the overall current flowing through the circuit (assuming the voltage stays the same).", "hint": "Think about how more resistance affects the flow of current, given a constant voltage."}, {"id": "sds82008", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which best describes the difference between heat and temperature?", "options": ["heat and temperature mean exactly the same thing", "temperature measures the average kinetic energy of particles, while heat refers to the total energy transferred between objects", "heat only applies to solids, temperature only applies to liquids", "temperature cannot be measured accurately"], "answer": 1, "exp": "Temperature measures the average kinetic energy of particles in a substance, while heat refers to the total thermal energy transferred between objects or substances.", "hint": "Think about the difference between measuring 'how energetic, on average' versus 'how much total energy is moving'."}, {"id": "sds82009", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Why does a metal handle on a saucepan get hot more quickly than a wooden or plastic handle?", "options": ["metal is always a darker colour, absorbing more light", "metal is a much better conductor of heat than wood or plastic", "wooden handles are always located further from the heat source", "this never actually happens"], "answer": 1, "exp": "Metal conducts heat much more efficiently than wood or plastic, allowing heat to travel quickly through the metal handle.", "hint": "Think about the heat-conducting properties of metal compared to wood or plastic."}, {"id": "sds82010", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Particle Theory", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "As a substance changes from a liquid to a gas (boiling/evaporating), what happens to the energy of its particles?", "options": ["the particles lose all their energy", "the particles gain enough energy to overcome the forces holding them together as a liquid, moving further apart", "the particles' energy has no connection to this change", "the particles merge into a single large particle"], "answer": 1, "exp": "As a liquid changes to a gas, its particles gain enough energy to overcome the attractive forces holding them close together, allowing them to spread far apart as a gas.", "hint": "Think about particles needing enough energy to 'break free' from the liquid state."}, {"id": "sds82011", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Particle Theory", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which best explains why ice floats on liquid water, despite both being made of the same substance?", "options": ["ice is actually a different substance from water", "ice has a slightly less dense particle arrangement than liquid water", "ice is always warmer than the surrounding water", "floating has nothing to do with density"], "answer": 1, "exp": "Water is unusual in that its solid form (ice) has a slightly less dense particle arrangement than its liquid form, allowing ice to float rather than sink.", "hint": "Think about density — for ice to float, it must be less dense than the liquid water around it."}, {"id": "sds82012", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which of these is an example of energy being transformed from electrical energy into light and heat energy?", "options": ["a light bulb glowing brightly", "a windmill spinning in the breeze", "a person walking up stairs", "a guitar string vibrating"], "answer": 0, "exp": "A light bulb transforms electrical energy into both light energy (its main purpose) and heat energy (an unavoidable by-product), as some energy is always lost as heat in this kind of transformation.", "hint": "Think about a device that runs on electricity and produces light, often becoming warm in the process."}, {"id": "sds82013", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which of these materials would be the best thermal insulator, keeping a drink cold for longer?", "options": ["a thin metal can", "a thick foam (polystyrene) cup", "a thin glass cup", "a thin plastic wrap only"], "answer": 1, "exp": "Thick foam contains many tiny pockets of trapped air, which conducts heat poorly, making it an effective thermal insulator that slows heat transfer.", "hint": "Think about a material containing lots of trapped air, which is a poor conductor of heat."}, {"id": "sds82014", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Why does stirring a hot drink with a metal spoon make the spoon's handle feel warm relatively quickly?", "options": ["the spoon generates its own heat", "heat is conducted along the metal spoon, from the hot liquid to the handle", "this never actually happens with metal spoons", "the spoon absorbs cold from the air"], "answer": 1, "exp": "Heat is conducted efficiently along the metal spoon, travelling from the hot liquid through the particles of the spoon, up to the handle.", "hint": "Think about heat travelling through the connected particles of the metal spoon."}, {"id": "sds82015", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Electricity", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "In a parallel circuit with two globes, what happens if one globe burns out and stops working?", "options": ["the entire circuit stops working immediately", "the other globe usually continues to work, since it has its own separate path for current", "the voltage in the circuit becomes zero", "both globes always burn out together"], "answer": 1, "exp": "In a parallel circuit, each component has its own separate path for current, so if one globe burns out, the other can usually continue working through its own path.", "hint": "Think about how parallel circuits provide multiple separate paths, unlike a series circuit's single path."}, {"id": "sds82016", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which of these best describes why a room with light-coloured walls might feel slightly different in temperature compared to a room with dark-coloured walls, under the same sunlight?", "options": ["light colours absorb more radiation, making the room hotter", "dark colours generally absorb more radiant energy than light colours, which can make a room warmer", "colour has no effect on radiant heat absorption at all", "light and dark colours absorb exactly the same amount of energy"], "answer": 1, "exp": "Dark colours generally absorb more radiant energy (heat) than light colours, which tend to reflect more radiation, which can make dark-walled rooms feel warmer under the same sunlight.", "hint": "Think about why people often wear lighter-coloured clothing in hot, sunny weather."}, {"id": "sds82017", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which best describes the energy transformation occurring when a battery powers a torch?", "options": ["chemical energy is transformed into electrical energy, then into light energy", "light energy is transformed into electrical energy", "kinetic energy is transformed into chemical energy", "no energy transformation occurs at all"], "answer": 0, "exp": "A battery stores chemical energy, which is transformed into electrical energy to power the torch, which is then transformed into light energy (and some heat).", "hint": "Think about the form of energy stored inside a battery before it powers anything."}, {"id": "sds82018", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Particle Theory", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Why do scientists use the particle model to explain states of matter, rather than simply describing what's visible to the naked eye?", "options": ["the particle model explains WHY substances behave as they do, based on the arrangement and movement of particles too small to see directly", "particles are visible to the naked eye, so this is simply more convenient", "the particle model has no real scientific value", "states of matter cannot be explained scientifically at all"], "answer": 0, "exp": "The particle model explains the underlying reasons for observable behaviours (like expansion, changes of state, and pressure), based on the arrangement and movement of particles too small to see directly.", "hint": "Think about why explaining the invisible cause behind a visible effect is scientifically useful."}, {"id": "sds82019", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "A thermos flask is designed with a vacuum layer between its inner and outer walls. Why is this effective at keeping drinks hot or cold?", "options": ["a vacuum has no particles, so it prevents heat transfer by conduction and convection", "a vacuum actively generates cold", "a vacuum increases heat transfer significantly", "this design has no real scientific basis"], "answer": 0, "exp": "Since a vacuum contains no particles, heat cannot be transferred through it by conduction or convection, which significantly slows heat loss or gain.", "hint": "Think about what conduction and convection both require in order to transfer heat — and what a vacuum lacks."}, {"id": "sds82020", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which of these scenarios demonstrates convection currents?", "options": ["a metal rod heating up along its length when one end is placed in a flame", "warm air near a heater rising, while cooler air sinks to take its place", "sunlight warming your skin on a sunny day", "two objects touching and reaching the same temperature"], "answer": 1, "exp": "This scenario describes convection — the circulating movement of a fluid (air) as warmer, less dense regions rise and cooler, denser regions sink to replace them.", "hint": "Look for the scenario describing fluid (air or liquid) actually moving and circulating."}, {"id": "sds82021", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which best explains why wearing several thin layers of clothing in cold weather is often more effective than wearing one thick layer?", "options": ["thin layers trap small pockets of air between them, which insulate effectively against heat loss", "thick layers always work better than thin layers", "clothing colour matters more than the number of layers", "layering clothes has no effect on insulation"], "answer": 0, "exp": "Multiple thin layers trap small pockets of air between them, and trapped air is a poor conductor of heat, providing effective insulation against heat loss.", "hint": "Think about what gets trapped between multiple layers of clothing, and how that affects heat loss."}, {"id": "sds82022", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Particle Theory — Changes of State", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "A solid is heated until it changes into a gas, without passing through a liquid state at standard atmospheric pressure (such as dry ice). What is this process called?", "options": ["melting", "condensation", "sublimation", "freezing"], "answer": 2, "exp": "Sublimation is the process of a solid changing directly into a gas, without passing through a liquid state, such as solid carbon dioxide (dry ice).", "hint": "Think about a solid 'skipping' the liquid stage entirely as it changes to a gas."}, {"id": "sds82023", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which best describes why touching metal feels colder than touching wood, even when both are at the same room temperature?", "options": ["metal is always naturally colder than wood", "metal conducts heat away from your hand much faster than wood, making it feel colder even at the same actual temperature", "wood actively generates warmth", "this sensation has nothing to do with heat conduction"], "answer": 1, "exp": "Even at the same room temperature, metal conducts heat away from your hand far more efficiently than wood, which is why it feels colder to the touch.", "hint": "Think about the rate at which heat leaves your hand into each material, not just the material's actual temperature."}, {"id": "sds82024", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which of these correctly ranks heat transfer methods needed to explain how heat from a campfire reaches a person sitting a few metres away?", "options": ["only conduction is involved", "mainly radiation, since heat travels through the air without needing direct particle-to-particle contact across that distance", "only convection is involved", "no heat transfer occurs across open air"], "answer": 1, "exp": "Heat from a campfire reaching a person a few metres away travels mainly by radiation, since this method doesn't require direct contact between particles across that distance.", "hint": "Think about how heat can travel through open air to reach you, without requiring direct contact through a solid material."}, {"id": "sds82025", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Energy Transfer — Heat", "difficulty": "hard", "style": "standard", "paper": "G8-S2", "q": "Which best describes why a bimetallic strip (made of two different metals joined together) bends when heated?", "options": ["the two metals expand at different rates when heated, causing the strip to curve", "both metals always expand at exactly the same rate", "heating a metal never causes any size change", "the strip bends only when cooled, not heated"], "answer": 0, "exp": "Different metals expand at different rates when heated. Since the two metals are joined together, this difference in expansion causes the strip to bend.", "hint": "Think about what happens when two materials that expand by different amounts are joined firmly together."}, {"id": "sds83001", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Rock Cycle", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which type of rock forms when magma or lava cools and solidifies?", "options": ["sedimentary", "igneous", "metamorphic", "none of these"], "answer": 1, "exp": "Igneous rocks form when molten rock (magma below the surface, or lava above it) cools and solidifies.", "hint": "Think about rocks formed directly from cooling molten material."}, {"id": "sds83002", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Rock Cycle", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which type of rock forms from layers of sediment that are compacted and cemented together over time?", "options": ["igneous", "sedimentary", "metamorphic", "none of these"], "answer": 1, "exp": "Sedimentary rocks form when layers of sediment (such as sand, silt, or organic material) are compacted and cemented together over long periods of time.", "hint": "Think about rocks formed from layers of material building up and compressing over time."}, {"id": "sds83003", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Rock Cycle", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which type of rock forms when existing rock is changed by intense heat and pressure, without melting completely?", "options": ["igneous", "sedimentary", "metamorphic", "none of these"], "answer": 2, "exp": "Metamorphic rocks form when existing rock is transformed by intense heat and pressure, changing its structure without fully melting.", "hint": "Think about rocks that are physically and chemically transformed by heat and pressure, but don't actually melt."}, {"id": "sds83004", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Plate Tectonics", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "What is the name for Earth's large, slowly moving sections of crust and upper mantle?", "options": ["volcanoes", "tectonic plates", "fault lines only", "sediment layers"], "answer": 1, "exp": "Tectonic plates are large sections of Earth's crust and upper mantle that move slowly over time, driven by forces within the mantle.", "hint": "This term describes the large, puzzle-piece-like sections that make up Earth's outer layer."}, {"id": "sds83005", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Plate Tectonics", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "What type of tectonic plate boundary occurs when two plates move apart from each other?", "options": ["convergent boundary", "divergent boundary", "transform boundary", "none of these"], "answer": 1, "exp": "A divergent boundary occurs where two tectonic plates move apart from each other, often allowing magma to rise and form new crust.", "hint": "Think about the word 'diverge', meaning to move apart or separate."}, {"id": "sds83006", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Plate Tectonics", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "What type of tectonic plate boundary occurs when two plates move toward and collide with each other, often forming mountains?", "options": ["convergent boundary", "divergent boundary", "transform boundary", "none of these"], "answer": 0, "exp": "A convergent boundary occurs where two tectonic plates move toward each other and collide, which can push up mountain ranges or cause one plate to sink beneath another.", "hint": "Think about the word 'converge', meaning to come together."}, {"id": "sds83007", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Plate Tectonics", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "What type of tectonic plate boundary occurs when two plates slide past each other horizontally, often causing earthquakes?", "options": ["convergent boundary", "divergent boundary", "transform boundary", "none of these"], "answer": 2, "exp": "A transform boundary occurs where two plates slide past each other horizontally, building up pressure that is released as earthquakes.", "hint": "Think about plates sliding past each other sideways, rather than colliding or separating."}, {"id": "sds83008", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Plate Tectonics", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "What causes most earthquakes?", "options": ["heavy rainfall only", "the sudden release of built-up pressure along tectonic plate boundaries", "changes in air temperature", "ocean tides moving"], "answer": 1, "exp": "Most earthquakes are caused by the sudden release of built-up pressure (stress) along tectonic plate boundaries, particularly transform and convergent boundaries.", "hint": "Think about pressure building up between two plates that are stuck against each other, then suddenly releasing."}, {"id": "sds83009", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Light", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which of these best describes how light travels?", "options": ["light travels in curved paths only", "light travels in straight lines, unless it passes through a different medium or is reflected", "light cannot travel through empty space", "light only travels when reflected off mirrors"], "answer": 1, "exp": "Light travels in straight lines (called rays) unless it is reflected off a surface or refracted as it passes into a different medium.", "hint": "Think about the basic, predictable path light takes when nothing interferes with it."}, {"id": "sds83010", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Light", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "What is the term for light bouncing off a surface?", "options": ["refraction", "reflection", "diffraction", "absorption"], "answer": 1, "exp": "Reflection is the term for light bouncing off a surface, such as light reflecting off a mirror.", "hint": "Think about what happens when light hits a mirror and bounces back."}, {"id": "sds83011", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Light", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "What is the term for light bending as it passes from one medium into another, such as from air into water?", "options": ["reflection", "refraction", "absorption", "emission"], "answer": 1, "exp": "Refraction is the bending of light as it passes from one medium into another, due to a change in speed.", "hint": "Think about why a straw looks bent when viewed through a glass of water."}, {"id": "sds83012", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Light", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Why does white light separate into a spectrum of colours when passing through a prism?", "options": ["the prism adds new colours to the light", "different colours of light have different wavelengths and refract by different amounts", "white light has no colours within it at all", "prisms only work with coloured light, not white light"], "answer": 1, "exp": "White light is made up of multiple colours, each with a different wavelength. As they pass through the prism, each colour refracts (bends) by a slightly different amount, separating them into a visible spectrum.", "hint": "Think about why each colour might bend by a slightly different amount as it passes through the glass."}, {"id": "sds83013", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "What determines the pitch of a sound?", "options": ["the volume of the source", "the frequency of the sound wave's vibrations", "the colour of the object producing the sound", "the distance the sound travels"], "answer": 1, "exp": "Pitch is determined by the frequency of a sound wave's vibrations — higher frequency vibrations produce higher pitched sounds.", "hint": "Think about how fast something vibrates, which directly relates to how high or low it sounds."}, {"id": "sds83014", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "What determines the loudness (volume) of a sound?", "options": ["the frequency of the wave", "the amplitude (size) of the sound wave's vibrations", "the colour of the object producing the sound", "the temperature of the room"], "answer": 1, "exp": "Loudness is determined by the amplitude of a sound wave — larger vibrations carry more energy, producing a louder sound.", "hint": "Think about how much energy is in the vibration, rather than how fast it vibrates."}, {"id": "sds83015", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Why can't sound travel through the vacuum of space?", "options": ["space is too cold for sound to exist", "sound requires a medium (like air, water, or a solid) of particles to vibrate through, and a vacuum has no particles", "sound waves are destroyed by sunlight", "sound only exists on Earth"], "answer": 1, "exp": "Sound is a vibration that travels through the particles of a medium (solid, liquid, or gas). Since a vacuum has no particles, sound cannot travel through it.", "hint": "Think about what sound actually needs to travel — and what a vacuum is missing."}, {"id": "sds83016", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which best describes why sound generally travels faster through solids than through air?", "options": ["solids have no particles at all", "particles in a solid are packed closely together, allowing vibrations to pass between them more quickly", "sound cannot travel through solids at all", "air always conducts sound faster than solids"], "answer": 1, "exp": "Particles in a solid are packed closely together, allowing vibrations to transfer between them more quickly than in the more widely spaced particles of air.", "hint": "Think about how closely packed particles are in a solid, compared to a gas like air."}, {"id": "sds83017", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which layer of rock and soil beneath the surface can store and supply groundwater?", "options": ["the crust only", "an aquifer", "the mantle", "the core"], "answer": 1, "exp": "An aquifer is a layer of rock and soil that can store and supply groundwater, often tapped by wells for drinking water.", "hint": "Think about the underground layer that can hold water like a natural reservoir."}, {"id": "sds83018", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Rock Cycle", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "What is the rock cycle?", "options": ["a one-way process where rocks only ever become sedimentary", "the continuous process by which rocks change between igneous, sedimentary, and metamorphic forms over time", "a cycle that only affects volcanic regions", "a process that occurs only once in Earth's history"], "answer": 1, "exp": "The rock cycle describes the continuous, ongoing process by which rocks change between igneous, sedimentary, and metamorphic forms, driven by heat, pressure, weathering, and erosion over long periods of time.", "hint": "Think about an ongoing, repeating cycle rather than a one-way, single process."}, {"id": "sds83019", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Plate Tectonics", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which of these is evidence supporting the theory of plate tectonics?", "options": ["matching fossil and rock patterns found on continents now separated by oceans", "the fact that all continents are exactly the same shape", "the complete absence of earthquakes anywhere on Earth", "the fact that mountains never form near plate boundaries"], "answer": 0, "exp": "Matching fossils and rock formations found on continents now separated by oceans (such as parts of South America and Africa) provide strong evidence that these continents were once joined together.", "hint": "Think about clues found on continents that are now far apart, but seem to match up."}, {"id": "sds83020", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Light", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which best explains why a pencil appears to bend at the point where it enters a glass of water?", "options": ["the pencil physically bends when wet", "light refracts (bends) as it passes from air into water, changing the apparent position of the pencil", "this is purely an optical illusion with no scientific cause", "water always magnifies objects placed inside it"], "answer": 1, "exp": "Light refracts as it passes from air into water, changing direction and creating the visual effect of the pencil appearing to bend at the water's surface.", "hint": "Think about the change in the speed and direction of light as it moves from air into a denser medium."}, {"id": "sds83021", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which best explains echo formation?", "options": ["sound waves disappearing into thin air", "sound waves reflecting off a surface and returning to the listener after a short delay", "sound waves only occurring underwater", "light waves bouncing off mirrors"], "answer": 1, "exp": "An echo occurs when sound waves reflect off a hard surface (like a cliff or wall) and return to the listener after a short delay.", "hint": "Think about sound 'bouncing back', similar to how light reflects off a mirror."}, {"id": "sds83022", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which of these best describes weathering?", "options": ["the breakdown of rock in place, due to factors like wind, water, ice, or chemical processes", "the movement of broken rock material to a new location", "the formation of new rock from magma", "the complete disappearance of rock with no remaining trace"], "answer": 0, "exp": "Weathering is the breakdown of rock in place (without movement), caused by factors such as wind, water, temperature changes, ice, or chemical processes.", "hint": "Think about a rock being broken down right where it is, without yet being carried away."}, {"id": "sds83023", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Plate Tectonics", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Why do some areas near plate boundaries experience frequent volcanic activity?", "options": ["plate boundaries have no connection to volcanic activity", "magma can rise more easily to the surface near plate boundaries, particularly at divergent and some convergent boundaries", "volcanoes only form in the middle of tectonic plates", "volcanic activity is completely random and unrelated to geology"], "answer": 1, "exp": "Near plate boundaries, particularly divergent boundaries and certain convergent boundaries, magma can rise more easily to the surface, leading to frequent volcanic activity.", "hint": "Think about why magma might find it easier to reach the surface specifically near the edges of tectonic plates."}, {"id": "sds83024", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Sound", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "A musical instrument's string is tightened, increasing its tension. What effect would this most likely have on the pitch of the sound it produces?", "options": ["the pitch would become lower", "the pitch would become higher", "there would be no change in pitch", "the string would stop producing sound entirely"], "answer": 1, "exp": "Tightening a string increases the frequency of its vibrations, which raises the pitch of the sound it produces.", "hint": "Think about how a tighter, more tense string vibrates compared to a looser one."}, {"id": "sds83025", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Earth Science — Rock Cycle", "difficulty": "hard", "style": "standard", "paper": "G8-S3", "q": "Which best describes the relationship between the three main rock types in the rock cycle?", "options": ["each rock type can eventually transform into either of the other two types, given the right conditions", "igneous rock can never become sedimentary rock", "metamorphic rock is the only starting point for the rock cycle", "once a rock forms, it can never change again"], "answer": 0, "exp": "In the rock cycle, each rock type can eventually transform into either of the other two types, given the right combination of heat, pressure, weathering, and time.", "hint": "Think about the 'cycle' part of the rock cycle — rocks can transform repeatedly, not just in one direction."}, {"id": "sds84001", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "In a food chain, what is the original source of energy for almost all life on Earth?", "options": ["the soil", "the Sun", "decomposers", "water"], "answer": 1, "exp": "The Sun is the original source of energy for almost all life on Earth, captured by producers (like plants) through photosynthesis.", "hint": "Think about the ultimate energy source that plants use to make their own food."}, {"id": "sds84002", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "What is a 'producer' in an ecosystem?", "options": ["an organism that eats other organisms for energy", "an organism that makes its own food, usually using sunlight (such as a plant)", "an organism that breaks down dead material", "a non-living part of the environment"], "answer": 1, "exp": "A producer is an organism, typically a plant, that makes its own food using sunlight through photosynthesis, forming the base of most food chains.", "hint": "Think about the organisms at the very start of a food chain, making their own food."}, {"id": "sds84003", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "What is a 'consumer' in an ecosystem?", "options": ["an organism that makes its own food", "an organism that obtains energy by eating other organisms", "a non-living part of the environment", "an organism that never needs energy"], "answer": 1, "exp": "A consumer obtains energy by eating other organisms, rather than producing its own food.", "hint": "Think about organisms that must eat other living things to get their energy."}, {"id": "sds84004", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems — Energy Flow", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "Approximately what percentage of energy is typically transferred from one trophic level to the next in a food chain?", "options": ["about 1%", "about 10%", "about 50%", "about 90%"], "answer": 1, "exp": "On average, only about 10% of energy is transferred from one trophic level to the next, with the rest lost mainly as heat through life processes like movement and respiration.", "hint": "Think about the commonly cited approximate figure used to describe energy loss between feeding levels."}, {"id": "sds84005", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems — Energy Flow", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "Why does energy decrease at each successive level of a food chain?", "options": ["energy is destroyed completely at each level", "much of the energy is used for life processes (like movement and growth) and lost as heat, rather than being passed on", "energy actually increases at each level", "there is no real energy loss in food chains"], "answer": 1, "exp": "At each level, organisms use much of their energy for life processes such as movement, growth, and maintaining body temperature, with this energy mostly lost as heat rather than passed on to the next level.", "hint": "Think about everything an organism uses energy for, besides simply being eaten by the next level."}, {"id": "sds84006", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems — Interdependence", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "What is a 'predator-prey relationship'?", "options": ["two species that never interact", "a relationship where one organism (the predator) hunts and eats another (the prey)", "a relationship where both organisms benefit equally", "a relationship that only exists in water ecosystems"], "answer": 1, "exp": "A predator-prey relationship describes the interaction where one organism (the predator) hunts and consumes another organism (the prey) for energy.", "hint": "Think about the classic 'hunter and hunted' relationship between two species."}, {"id": "sds84007", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems — Interdependence", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "What might happen to a prey population if its main predator suddenly disappeared from an ecosystem?", "options": ["the prey population would likely increase, at least initially, due to reduced predation", "the prey population would immediately disappear too", "there would be absolutely no effect on the prey population", "the prey would automatically become predators themselves"], "answer": 0, "exp": "Without its main predator, a prey population would likely increase, at least initially, since fewer individuals are being hunted — though this can lead to other ecosystem effects, like resource shortages.", "hint": "Think about what typically happens to a population when one of its major threats is removed."}, {"id": "sds84008", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems — Interdependence", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "What is 'mutualism' in ecology?", "options": ["a relationship where one organism benefits and the other is harmed", "a relationship where both organisms benefit", "a relationship where neither organism is affected", "a type of food chain only"], "answer": 1, "exp": "Mutualism describes a relationship between two different species where both organisms benefit, such as bees pollinating flowers while gaining nectar.", "hint": "Think about a relationship that benefits BOTH species involved, not just one."}, {"id": "sds84009", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems — Interdependence", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "What is 'competition' in an ecosystem?", "options": ["organisms working together for a shared goal", "organisms competing for the same limited resources, such as food, water, or space", "a type of predator-prey relationship only", "a relationship that always benefits both organisms"], "answer": 1, "exp": "Competition occurs when organisms (of the same or different species) compete for the same limited resources, such as food, water, or space.", "hint": "Think about organisms competing against each other for something in short supply."}, {"id": "sds84010", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "A scientist investigates whether fertiliser concentration affects plant growth, testing five different concentrations while keeping water, light, and soil type constant. What is the independent variable in this investigation?", "options": ["the amount of water given", "fertiliser concentration", "plant growth (height)", "soil type"], "answer": 1, "exp": "The independent variable is the one deliberately changed by the scientist — in this case, the fertiliser concentration being tested at five different levels.", "hint": "Look for the variable the scientist is intentionally changing across the five test groups."}, {"id": "sds84011", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "In the same investigation, what is the dependent variable?", "options": ["fertiliser concentration", "plant growth (height), since this is what is measured as a result", "the type of soil used", "the temperature of the room"], "answer": 1, "exp": "The dependent variable is what is measured as a result of the investigation — in this case, plant growth (height), which may change depending on the fertiliser concentration.", "hint": "Look for the variable being measured, which depends on what's being tested."}, {"id": "sds84012", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "Why is it important for this investigation to use multiple plants at each fertiliser concentration, rather than just one plant per group?", "options": ["it makes the investigation take less time", "it improves reliability, reducing the impact of natural variation between individual plants", "it has no real scientific benefit", "using only one plant per group is always more accurate"], "answer": 1, "exp": "Using multiple plants at each concentration improves reliability by reducing the impact of natural variation between individual plants, giving a more accurate overall picture of the fertiliser's effect.", "hint": "Think about why a single plant might not fairly represent the typical effect of a given fertiliser level."}, {"id": "sds84013", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Scientific Method — Data Presentation", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "Which type of graph would be most appropriate for displaying the relationship between fertiliser concentration (a continuous variable) and average plant height?", "options": ["a pie chart", "a line graph or scatter plot", "a Venn diagram", "a simple yes/no table"], "answer": 1, "exp": "A line graph or scatter plot is well suited to showing the relationship between two continuous, numerical variables, such as fertiliser concentration and plant height.", "hint": "Think about a graph type designed to show a relationship between two sets of numerical data."}, {"id": "sds84014", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "What is the purpose of a 'control group' that receives no fertiliser at all in this investigation?", "options": ["to provide a baseline for comparison against the fertilised groups", "to waste resources intentionally", "control groups are not actually necessary in this type of investigation", "to test a completely unrelated variable"], "answer": 0, "exp": "A control group with no fertiliser provides a baseline for comparison, helping the scientist determine how much of an effect, if any, the fertiliser is actually having.", "hint": "Think about needing something to compare the fertilised groups against, to know if fertiliser is really making a difference."}, {"id": "sds84015", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "Which best describes a 'food web', as opposed to a simple food chain?", "options": ["a food web shows only one possible path of energy flow", "a food web shows multiple interconnected feeding relationships among many different organisms in an ecosystem", "a food web only applies to ocean ecosystems", "a food web and a food chain are exactly the same thing"], "answer": 1, "exp": "A food web shows multiple interconnected feeding relationships among many different organisms, providing a more complete and realistic picture than a single, simple food chain.", "hint": "Think about how a 'web' suggests many connections, rather than a single simple path."}, {"id": "sds84016", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems — Interdependence", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "What might happen to an ecosystem if an introduced (non-native) predator species is released with no natural predators of its own?", "options": ["the ecosystem would be completely unaffected", "native prey populations could decline sharply, potentially disrupting the whole food web", "the introduced species would always die out immediately", "introduced species can never affect existing ecosystems"], "answer": 1, "exp": "Without natural predators to control its population, an introduced predator could cause native prey populations to decline sharply, disrupting the existing food web and broader ecosystem balance.", "hint": "Think about what happens when a new predator enters an ecosystem with no checks on its own population."}, {"id": "sds84017", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "A student wants to test how light intensity affects the rate of photosynthesis in a water plant, measured by counting oxygen bubbles produced per minute. Which variable should be kept constant to ensure a fair test?", "options": ["light intensity", "the type and amount of plant material used, along with water temperature", "the number of bubbles counted", "the time of day the experiment is conducted, since this has no real effect"], "answer": 1, "exp": "To ensure a fair test, variables like the type and amount of plant material, and water temperature, should be kept constant, so that light intensity is the only variable affecting the bubble count.", "hint": "Think about what else could affect the rate of photosynthesis, besides light intensity, that needs to be controlled."}, {"id": "sds84018", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "Which best describes a 'population' versus a 'community' in ecological terms?", "options": ["a population includes all species in an area, while a community includes only one species", "a population includes only one species in an area, while a community includes all the different populations interacting together", "population and community mean exactly the same thing", "a population only refers to human groups"], "answer": 1, "exp": "A population refers to all the individuals of ONE species in an area, while a community includes all the different populations (of different species) interacting together.", "hint": "Think about the difference between counting just one species versus counting all the different species together."}, {"id": "sds84019", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "In an investigation testing the effect of temperature on enzyme activity, why might a scientist choose to repeat each temperature trial three times?", "options": ["to waste laboratory materials", "to calculate an average result, improving reliability and reducing the impact of unusual one-off results", "repeating trials is never useful in science", "to make the experiment take less time overall"], "answer": 1, "exp": "Repeating trials allows a scientist to calculate an average result, improving reliability and reducing the impact of unusual one-off results (anomalies) on the overall conclusion.", "hint": "Think about how averaging several results can give a more trustworthy overall picture than a single trial."}, {"id": "sds84020", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "Which best explains why decomposers are essential to the long-term functioning of an ecosystem?", "options": ["they have no real ecological function", "they recycle nutrients from dead organisms and waste back into the ecosystem, making them available to producers again", "they only exist in aquatic ecosystems", "they directly compete with producers for sunlight"], "answer": 1, "exp": "Decomposers break down dead organisms and waste, recycling essential nutrients back into the soil or water, making them available for producers to use again.", "hint": "Think about what would happen to nutrients locked inside dead organisms if nothing ever broke them down."}, {"id": "sds84021", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "A scientist's data shows a correlation between two variables, but the scientist cautions that 'correlation does not necessarily imply causation'. What does this caution mean?", "options": ["the two variables are definitely unrelated", "just because two variables are related doesn't prove that one directly causes changes in the other", "correlation is always the same thing as causation", "this caution applies only to ecological studies"], "answer": 1, "exp": "This caution means that even when two variables show a clear relationship (correlation), this alone doesn't prove that changes in one variable directly cause changes in the other — there could be other explanations.", "hint": "Think about other possible explanations for why two things might appear related, besides one directly causing the other."}, {"id": "sds84022", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "Which best describes 'carrying capacity' in an ecosystem?", "options": ["the maximum weight an ecosystem can physically support", "the maximum population size that an ecosystem's resources can sustainably support over time", "a measurement of an ecosystem's total land area", "a fixed number that never changes for any ecosystem"], "answer": 1, "exp": "Carrying capacity is the maximum population size that an ecosystem's available resources (food, water, space) can sustainably support over time.", "hint": "Think about the limit on how many individuals an environment's resources can actually support long-term."}, {"id": "sds84023", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "Why might scientific conclusions be considered more reliable when published findings can be reviewed and repeated by other independent scientists?", "options": ["independent verification helps confirm whether results are genuine and not due to error, bias, or chance", "review by other scientists has no real value", "published findings are always correct without any need for review", "repeating an experiment by others is generally discouraged in science"], "answer": 0, "exp": "Independent verification by other scientists helps confirm whether results are genuine, rather than the result of error, bias, or chance, strengthening confidence in the overall scientific conclusion.", "hint": "Think about why having other, independent people check and repeat a result adds credibility to scientific findings."}, {"id": "sds84024", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "A study observes that ice cream sales and shark attacks both increase during summer months. Which best explains this correlation, without assuming ice cream causes shark attacks?", "options": ["ice cream directly causes sharks to attack swimmers", "both ice cream sales and shark attacks are independently linked to a third factor — warmer weather, which increases both ice cream consumption and beach swimming", "shark attacks directly cause people to buy more ice cream", "there is no possible explanation for this pattern"], "answer": 1, "exp": "This is a classic example of a third, underlying factor (warmer weather) independently causing both increased ice cream sales and increased beach swimming (and therefore shark encounters), rather than either variable causing the other directly.", "hint": "Think about a third factor, like the season, that could independently explain both increases."}, {"id": "sds84025", "state": "AU", "section": "sec_science", "grade": "8", "topic": "Ecosystems", "difficulty": "hard", "style": "standard", "paper": "G8-S4", "q": "Which best describes the difference between a 'habitat' and a 'niche'?", "options": ["a habitat is the physical place an organism lives, while a niche is the specific role it plays within that ecosystem", "habitat and niche mean exactly the same thing", "a niche refers only to predators, while habitat refers only to prey", "habitats and niches only apply to plant species"], "answer": 0, "exp": "A habitat is the physical place where an organism lives, while a niche describes the specific role it plays within its ecosystem, including how it obtains food and interacts with other species.", "hint": "Think about the difference between WHERE an organism lives and WHAT specific role it plays there."}, {"id": "sds91001", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Atomic Structure", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "What are the three main subatomic particles that make up an atom?", "options": ["protons, neutrons, and electrons", "protons, molecules, and electrons", "neutrons, ions, and atoms", "electrons, compounds, and protons"], "answer": 0, "exp": "Atoms are made up of protons and neutrons (found in the nucleus) and electrons (orbiting the nucleus).", "hint": "Think about the three particles found in every atom, including the ones in the central nucleus."}, {"id": "sds91002", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Atomic Structure", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Where are protons and neutrons located within an atom?", "options": ["orbiting the nucleus", "in the nucleus, at the centre of the atom", "outside the atom entirely", "in the electron cloud only"], "answer": 1, "exp": "Protons and neutrons are located in the nucleus, the dense central core of an atom.", "hint": "Think about the central, dense part of an atom, distinct from the surrounding electrons."}, {"id": "sds91003", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Atomic Structure", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "What determines an element's atomic number?", "options": ["the number of neutrons in its nucleus", "the number of protons in its nucleus", "the number of electrons in its outer shell only", "the total mass of the atom"], "answer": 1, "exp": "An element's atomic number is determined by the number of protons in its nucleus, which is unique to each element.", "hint": "This number is what distinguishes one element from another on the periodic table."}, {"id": "sds91004", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Atomic Structure", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "What is an 'isotope'?", "options": ["an atom with a different number of protons than usual", "an atom of the same element with a different number of neutrons", "a completely different element", "a type of chemical bond"], "answer": 1, "exp": "Isotopes are atoms of the same element (same number of protons) but with a different number of neutrons, giving them a different atomic mass.", "hint": "Think about atoms of the same element that vary only in their neutron count."}, {"id": "sds91005", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Periodic Table", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which of these best describes the modern periodic table's organisation?", "options": ["elements are arranged randomly", "elements are arranged by increasing atomic number, with similar properties grouped in columns", "elements are arranged alphabetically only", "elements are arranged by colour"], "answer": 1, "exp": "The periodic table arranges elements by increasing atomic number, with columns (groups) containing elements that share similar chemical properties.", "hint": "Think about the systematic order based on a specific numerical property, with similar elements grouped together."}, {"id": "sds91006", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Periodic Table", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Elements in the same group (column) of the periodic table tend to have similar properties because they have the same number of what?", "options": ["protons", "neutrons", "electrons in their outer (valence) shell", "total electrons"], "answer": 2, "exp": "Elements in the same group share the same number of electrons in their outer (valence) shell, which largely determines their chemical behaviour.", "hint": "Think about the electrons most directly involved in forming chemical bonds."}, {"id": "sds91007", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Bonding", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "What is an 'ionic bond'?", "options": ["a bond formed by sharing electrons equally between atoms", "a bond formed by the attraction between oppositely charged ions, typically between a metal and a non-metal", "a bond that only forms between identical atoms", "a type of physical (not chemical) bond"], "answer": 1, "exp": "An ionic bond forms through the attraction between oppositely charged ions, typically created when a metal transfers electrons to a non-metal.", "hint": "Think about a bond involving the transfer of electrons, creating charged particles that attract each other."}, {"id": "sds91008", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Bonding", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "What is a 'covalent bond'?", "options": ["a bond formed by the transfer of electrons between atoms", "a bond formed by atoms sharing pairs of electrons, typically between two non-metals", "a bond that only exists in metals", "a type of physical mixture"], "answer": 1, "exp": "A covalent bond forms when atoms share pairs of electrons, typically occurring between two non-metal atoms.", "hint": "Think about a bond formed through sharing, rather than transferring, electrons."}, {"id": "sds91009", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Formulas", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "In the chemical formula H₂O, what does the subscript '2' tell you?", "options": ["there are 2 oxygen atoms", "there are 2 hydrogen atoms in each molecule", "the molecule has a charge of 2", "there are 2 molecules of water"], "answer": 1, "exp": "The subscript '2' after H indicates there are 2 hydrogen atoms in each water molecule, alongside 1 oxygen atom.", "hint": "A subscript number indicates how many atoms of that specific element are in one molecule."}, {"id": "sds91010", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Periodic Table", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which of these is a metal, based on typical periodic table position and properties?", "options": ["oxygen", "sodium", "chlorine", "neon"], "answer": 1, "exp": "Sodium is a metal, typically found on the left side of the periodic table, known for being shiny, conductive, and reactive.", "hint": "Think about an element typically found on the left side of the periodic table."}, {"id": "sds91011", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Periodic Table", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which of these is a noble gas, known for being largely unreactive?", "options": ["sodium", "chlorine", "neon", "oxygen"], "answer": 2, "exp": "Neon is a noble gas, found in the far right column of the periodic table, known for being largely unreactive due to having a full outer electron shell.", "hint": "Think about the far-right column of the periodic table, known for unreactive elements."}, {"id": "sds91012", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Periodic Table", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Why are noble gases generally unreactive?", "options": ["they have no electrons at all", "they have a full outer electron shell, making them stable and unlikely to form bonds", "they only exist at extremely high temperatures", "they are radioactive"], "answer": 1, "exp": "Noble gases have a full outer electron shell, making them chemically stable and generally unwilling to form bonds with other atoms.", "hint": "Think about why having a 'full' outer shell of electrons would make an atom stable and unreactive."}, {"id": "sds91013", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Density", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "A metal block has a mass of 15 g and a volume of 5 mL. What is its density?", "options": ["2 g/mL", "3 g/mL", "5 g/mL", "75 g/mL"], "answer": 1, "exp": "Step 1: Density = mass ÷ volume. Step 2: 15 ÷ 5 = 3 g/mL.", "hint": "Divide the mass by the volume."}, {"id": "sds91014", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Bonding", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which of these correctly describes how ions form?", "options": ["atoms losing or gaining protons", "atoms losing or gaining electrons, creating an overall electrical charge", "atoms losing or gaining neutrons only", "molecules splitting in half"], "answer": 1, "exp": "Ions form when atoms lose or gain electrons, resulting in an overall positive (losing electrons) or negative (gaining electrons) charge.", "hint": "Think about which subatomic particle is actually transferred to create a charged ion."}, {"id": "sds91015", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Bonding", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which of these best describes a 'molecule'?", "options": ["a single, isolated atom", "two or more atoms chemically bonded together", "a type of subatomic particle", "a mixture of unrelated substances"], "answer": 1, "exp": "A molecule is formed when two or more atoms are chemically bonded together, such as O₂ (two oxygen atoms) or H₂O (water).", "hint": "Think about atoms joining together through chemical bonds, rather than existing alone."}, {"id": "sds91016", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Formulas", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "In the chemical formula CO₂, how many total atoms are present in one molecule?", "options": ["1", "2", "3", "4"], "answer": 2, "exp": "CO₂ contains 1 carbon atom and 2 oxygen atoms, giving a total of 3 atoms in one molecule.", "hint": "Add up the number of each type of atom shown in the formula."}, {"id": "sds91017", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Bonding", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which best describes the difference between a mixture and a compound?", "options": ["a mixture and a compound are exactly the same thing", "in a compound, elements are chemically bonded in fixed proportions; in a mixture, substances are simply combined and can usually be physically separated", "mixtures can never be separated", "compounds are always liquids"], "answer": 1, "exp": "In a compound, elements are chemically bonded in a fixed ratio (such as H₂O), while in a mixture, substances are simply combined without chemical bonding and can usually be physically separated.", "hint": "Think about whether the substances are chemically joined in a fixed way, or simply combined physically."}, {"id": "sds91018", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Bonding", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which of these elements would most likely form a covalent bond with another non-metal, rather than an ionic bond?", "options": ["sodium and chlorine", "carbon and oxygen", "calcium and oxygen", "potassium and fluorine"], "answer": 1, "exp": "Carbon and oxygen are both non-metals, and bonds between two non-metals are typically covalent, formed through sharing electrons.", "hint": "Look for the pairing where BOTH elements are non-metals, rather than a metal and a non-metal."}, {"id": "sds91019", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Atomic Structure", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which subatomic particle has essentially no significant mass compared to protons and neutrons?", "options": ["protons", "neutrons", "electrons", "none of these — all three have equal mass"], "answer": 2, "exp": "Electrons have a mass that is roughly 1/1800th of a proton or neutron, making their contribution to an atom's overall mass essentially negligible by comparison.", "hint": "Think about the particle that orbits the nucleus, far lighter than the particles within it."}, {"id": "sds91020", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Formulas", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which of these best describes a 'chemical formula' such as NaCl?", "options": ["a description of how a substance looks", "a representation showing the types and ratios of atoms present in a compound", "a measurement of temperature", "a description of a substance's colour only"], "answer": 1, "exp": "A chemical formula like NaCl shows the types of atoms present (sodium and chlorine) and their ratio (1:1) within the compound.", "hint": "Think about what information a formula like this actually conveys about a substance's composition."}, {"id": "sds91021", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Bonding", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Why do metals tend to lose electrons easily when forming ionic bonds?", "options": ["metals typically have few electrons in their outer shell, making it easier to lose them and achieve a stable configuration", "metals have no electrons at all", "metals always gain electrons instead", "metals never participate in ionic bonding"], "answer": 0, "exp": "Metals typically have few electrons in their outer shell, making it energetically favourable to lose these electrons (rather than gain many more) to achieve a stable, full outer shell.", "hint": "Think about how many electrons a typical metal atom has in its outer shell, and which is easier: losing a few, or gaining many?"}, {"id": "sds91022", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Atomic Structure", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which of these correctly describes the relative size of an atom's nucleus compared to the whole atom?", "options": ["the nucleus takes up most of the atom's total volume", "the nucleus is extremely small compared to the overall size of the atom, which is mostly empty space occupied by the electron cloud", "the nucleus and the whole atom are the same size", "atoms have no defined size at all"], "answer": 1, "exp": "The nucleus is extremely small compared to the overall size of the atom, with most of the atom's volume being empty space occupied by the surrounding electron cloud.", "hint": "Think about how concentrated the protons and neutrons are, compared to the much larger space the electrons occupy."}, {"id": "sds91023", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Bonding", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which of these would most likely form an ionic bond?", "options": ["two oxygen atoms", "carbon and hydrogen", "sodium and chlorine", "two nitrogen atoms"], "answer": 2, "exp": "Sodium (a metal) and chlorine (a non-metal) typically form an ionic bond, with sodium losing an electron to chlorine.", "hint": "Look for the pairing involving one metal and one non-metal."}, {"id": "sds91024", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Atomic Structure", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which best describes why isotopes of the same element have different atomic masses?", "options": ["they have different numbers of protons", "they have different numbers of neutrons, despite having the same number of protons", "they have different numbers of electrons only", "isotopes always have identical atomic masses"], "answer": 1, "exp": "Isotopes have the same number of protons (defining the element) but different numbers of neutrons, which changes their overall atomic mass.", "hint": "Remember that isotopes share the same proton count but differ in another subatomic particle."}, {"id": "sds91025", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Chemical Formulas", "difficulty": "hard", "style": "standard", "paper": "G9-S1", "q": "Which best describes a 'chemical formula' such as H₂O?", "options": ["it shows the colour of a substance", "it shows the types and numbers of atoms in a compound", "it shows only the mass of a substance", "it shows the temperature at which a substance boils"], "answer": 1, "exp": "A chemical formula like H₂O shows the types of atoms present (hydrogen and oxygen) and how many of each are in one molecule of the compound (two hydrogen, one oxygen).", "hint": "Think about what the letters and small numbers in a formula actually represent."}, {"id": "sds92001", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "What is DNA, and what is its main function in cells?", "options": ["a type of protein that provides energy", "the genetic material that carries instructions for an organism's traits", "a structure that only exists in plant cells", "a waste product removed from cells"], "answer": 1, "exp": "DNA (deoxyribonucleic acid) is the genetic material found in cells, carrying the instructions that determine an organism's inherited traits.", "hint": "Think about the molecule that contains the 'instructions' for building and running a living organism."}, {"id": "sds92002", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "What is a 'gene'?", "options": ["an entire chromosome", "a section of DNA that contains instructions for a particular trait", "a type of cell found only in animals", "a structure that has no real biological function"], "answer": 1, "exp": "A gene is a specific section of DNA that contains the instructions for a particular inherited trait, such as eye colour.", "hint": "Think about a smaller, specific section within the much longer DNA molecule."}, {"id": "sds92003", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "In genetics, what is an 'allele'?", "options": ["a different version of a gene", "an entire organism's genetic code", "a type of chromosome found only in females", "a cell that has no genetic material"], "answer": 0, "exp": "An allele is a different version of a particular gene — for example, different alleles might code for brown eyes versus blue eyes.", "hint": "Think about the different possible 'versions' of a single gene."}, {"id": "sds92004", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "What does it mean if an organism is 'homozygous' for a particular trait?", "options": ["it has two different alleles for that trait", "it has two identical alleles for that trait", "it has no alleles for that trait at all", "it can only pass on one allele to offspring"], "answer": 1, "exp": "Homozygous means an organism has two identical alleles (both dominant, or both recessive) for a particular trait.", "hint": "Think about the prefix 'homo-', meaning 'same'."}, {"id": "sds92005", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "What does it mean if an organism is 'heterozygous' for a particular trait?", "options": ["it has two identical alleles for that trait", "it has two different alleles for that trait", "it has no genetic material for that trait", "it always shows the recessive trait"], "answer": 1, "exp": "Heterozygous means an organism has two different alleles (one dominant, one recessive) for a particular trait.", "hint": "Think about the prefix 'hetero-', meaning 'different'."}, {"id": "sds92006", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Punnett Squares", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "In a Punnett square, a cross between a homozygous dominant parent (TT) and a homozygous recessive parent (tt) produces offspring with which genotype?", "options": ["all TT", "all tt", "all Tt (heterozygous)", "a mix of TT, Tt, and tt"], "answer": 2, "exp": "Since one parent can only contribute a 'T' allele and the other can only contribute a 't' allele, every offspring will be Tt (heterozygous).", "hint": "Think about which allele each parent is able to contribute, given their genotype."}, {"id": "sds92007", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Punnett Squares", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "In a Punnett square cross between two heterozygous parents (Tt × Tt), what fraction of offspring would be expected to show the recessive trait (tt)?", "options": ["1/4", "1/2", "3/4", "all of them"], "answer": 0, "exp": "A Tt × Tt cross produces a typical ratio of 1 TT : 2 Tt : 1 tt, meaning 1 out of 4 (1/4) offspring would be expected to show the recessive trait (tt).", "hint": "Draw out the four possible combinations of alleles from this cross to find the ratio."}, {"id": "sds92008", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Dominant and Recessive Traits", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "If brown eyes (B) is dominant over blue eyes (b), what eye colour would an organism with the genotype Bb most likely have?", "options": ["brown", "blue", "a mix of both colours in each eye", "neither — this genotype is not possible"], "answer": 0, "exp": "Since brown (B) is dominant, an organism with at least one dominant allele (Bb) will show the dominant trait — brown eyes.", "hint": "Remember that a dominant allele will be expressed even if only one copy is present."}, {"id": "sds92009", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "What is the difference between an organism's 'genotype' and its 'phenotype'?", "options": ["genotype and phenotype mean exactly the same thing", "genotype refers to the genetic makeup (alleles), while phenotype refers to the observable physical trait", "phenotype refers only to behaviour, never physical traits", "genotype can be observed directly by looking at an organism"], "answer": 1, "exp": "Genotype refers to an organism's actual genetic makeup (its alleles), while phenotype refers to the observable physical trait that results from that genetic makeup.", "hint": "Think about the difference between the underlying genetic code and the visible result of that code."}, {"id": "sds92010", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Reproduction", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "Which best describes 'sexual reproduction' in terms of genetic variation?", "options": ["offspring are genetically identical to a single parent", "offspring inherit a combination of genetic material from two parents, increasing genetic variation", "sexual reproduction always produces less genetic variation than asexual reproduction", "sexual reproduction does not involve genetic material at all"], "answer": 1, "exp": "Sexual reproduction combines genetic material from two parents, creating new combinations of alleles in offspring and increasing genetic variation within a population.", "hint": "Think about how combining genetic material from two different sources affects variety among offspring."}, {"id": "sds92011", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Reproduction", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "Which best describes 'asexual reproduction'?", "options": ["it always requires two parents", "offspring are produced from a single parent and are typically genetically identical to that parent", "it always produces highly varied offspring", "it is impossible in any living organism"], "answer": 1, "exp": "Asexual reproduction involves a single parent producing offspring that are typically genetically identical (or nearly identical) to that parent, since there's no combination of genetic material from two sources.", "hint": "Think about reproduction involving only one parent, with no mixing of genetic material."}, {"id": "sds92012", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Mutations", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "What is a 'mutation' in genetics?", "options": ["a planned change made deliberately by a scientist", "a change in the DNA sequence, which can occur naturally and may or may not affect an organism's traits", "a type of chromosome found only in bacteria", "a process that always immediately kills an organism"], "answer": 1, "exp": "A mutation is a change in the DNA sequence, which can occur naturally. Mutations may have no effect, a harmful effect, or occasionally a beneficial effect on an organism.", "hint": "Think about a random change occurring in the genetic code itself, not a deliberate change."}, {"id": "sds92013", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Mutations", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "Why might genetic mutations be important for the long-term survival of a species?", "options": ["mutations always immediately harm a population", "mutations can occasionally introduce new, potentially beneficial traits, which natural selection may favour over time", "mutations have no real long-term significance", "mutations only occur in extinct species"], "answer": 1, "exp": "Mutations can occasionally introduce new traits into a population. If a trait happens to be beneficial in a particular environment, natural selection may favour individuals carrying it over time.", "hint": "Think about how new genetic variation could occasionally turn out to be helpful, even though most mutations are neutral or harmful."}, {"id": "sds92014", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Punnett Squares", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "In a Punnett square cross between a heterozygous parent (Aa) and a homozygous recessive parent (aa), what fraction of offspring would be expected to be heterozygous (Aa)?", "options": ["1/4", "1/2", "3/4", "1"], "answer": 1, "exp": "This cross produces a typical ratio of 2 Aa : 2 aa (or simplified, 1 Aa : 1 aa), meaning 1/2 (50%) of offspring would be expected to be heterozygous.", "hint": "Draw out the four possible offspring combinations from this specific cross."}, {"id": "sds92015", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "Which structure within a cell contains most of an organism's DNA?", "options": ["the cytoplasm", "the nucleus", "the cell membrane", "the mitochondria"], "answer": 1, "exp": "The nucleus contains most of a cell's DNA, organised into structures called chromosomes.", "hint": "Think about the structure that acts as the cell's genetic 'control centre'."}, {"id": "sds92016", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "What is a 'chromosome'?", "options": ["a single protein molecule", "a tightly coiled structure made of DNA, which carries many genes", "a type of cell membrane", "a waste product of cell division"], "answer": 1, "exp": "A chromosome is a tightly coiled structure made of DNA, carrying many genes along its length.", "hint": "Think about how the long DNA molecule is packaged neatly inside the cell's nucleus."}, {"id": "sds92017", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "How many chromosomes are typically found in a normal human body cell?", "options": ["23", "46", "92", "100"], "answer": 1, "exp": "A typical human body cell contains 46 chromosomes, arranged as 23 pairs (one set inherited from each parent).", "hint": "Think about chromosomes coming in pairs — 23 pairs in total."}, {"id": "sds92018", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Reproduction", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "Why do offspring typically inherit traits from both parents in sexual reproduction?", "options": ["offspring receive one set of chromosomes from each parent, combining genetic material from both", "only the mother's genetic material is ever passed on", "only the father's genetic material is ever passed on", "offspring create entirely new genetic material with no connection to either parent"], "answer": 0, "exp": "In sexual reproduction, offspring receive one set of chromosomes from each parent, combining genetic material from both into a new, unique combination.", "hint": "Think about each parent contributing exactly half of the offspring's total chromosomes."}, {"id": "sds92019", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Variation", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "Which best explains why two siblings from the same parents can look quite different from each other?", "options": ["siblings always have identical DNA", "each sibling inherits a different, random combination of alleles from their parents", "siblings cannot actually share the same parents", "differences between siblings are always caused by mutations only"], "answer": 1, "exp": "Each offspring inherits a different, randomly combined set of alleles from their parents, which is why siblings can show noticeably different traits despite sharing the same parents.", "hint": "Think about how each pregnancy involves a fresh, random combination of alleles, even from the same two parents."}, {"id": "sds92020", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Selective Breeding", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "In selective breeding, why might a farmer choose to breed only the largest, healthiest animals in a herd?", "options": ["to increase the likelihood that desirable traits, like size and health, are passed on to future generations", "selective breeding has no real effect on offspring traits", "to ensure all future animals are genetically identical clones", "this practice has no connection to genetics at all"], "answer": 0, "exp": "By selectively breeding animals with desirable traits, farmers increase the likelihood that genes associated with those traits (like size and health) are passed on to future generations.", "hint": "Think about deliberately choosing parents with traits you want to see more of in their offspring."}, {"id": "sds92021", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "Which best describes the relationship between genes and proteins in an organism?", "options": ["genes have no connection to proteins at all", "many genes contain instructions used by the cell to build specific proteins, which carry out many of the body's functions", "proteins create new genes", "genes and proteins are exactly the same thing"], "answer": 1, "exp": "Many genes contain the instructions a cell uses to build specific proteins, and these proteins go on to perform many of the body's essential functions.", "hint": "Think about genes as 'instructions' that the cell follows to actually build something useful — a protein."}, {"id": "sds92022", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Punnett Squares", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "A pea plant with the genotype Rr (where R = round seeds, dominant, and r = wrinkled seeds, recessive) is crossed with another Rr plant. Approximately what percentage of offspring would be expected to have wrinkled seeds?", "options": ["0%", "25%", "50%", "75%"], "answer": 1, "exp": "An Rr × Rr cross produces a typical ratio of 1 RR : 2 Rr : 1 rr, meaning approximately 25% (1 in 4) of offspring would be expected to show the recessive wrinkled-seed trait (rr).", "hint": "Draw out the four possible combinations from this cross to find the expected ratio."}, {"id": "sds92023", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Natural Selection", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "Which best describes 'natural selection'?", "options": ["organisms are deliberately bred by humans for specific traits", "individuals with traits better suited to their environment tend to survive and reproduce more successfully, passing those traits on", "all individuals in a species have an exactly equal chance of survival", "natural selection only applies to extinct species"], "answer": 1, "exp": "Natural selection describes how individuals with traits better suited to their environment tend to survive and reproduce more successfully, gradually increasing the frequency of those traits in a population over generations.", "hint": "Think about traits that give an individual a survival or reproductive advantage in their specific environment."}, {"id": "sds92024", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Reproduction", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "Why are identical twins genetically identical to each other?", "options": ["they develop from two separate fertilised eggs", "they develop from a single fertilised egg that splits into two early in development", "they share only half of their DNA, like regular siblings", "this is simply a coincidence with no genetic explanation"], "answer": 1, "exp": "Identical twins develop from a single fertilised egg that splits into two separate embryos early in development, meaning both share exactly the same genetic material.", "hint": "Think about the difference between starting from one fertilised egg versus two separate ones."}, {"id": "sds92025", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Genetics — Punnett Squares", "difficulty": "hard", "style": "standard", "paper": "G9-S2", "q": "A man with blood type genotype IAi (heterozygous for type A, where i is recessive) has children with a woman of genotype ii (type O). What blood type genotypes are possible in their children?", "options": ["only IAi", "only ii", "either IAi or ii", "only IAIA"], "answer": 2, "exp": "Step 1: The father can pass on either IA or i. Step 2: The mother can only pass on i. Step 3: Possible children genotypes are IAi (type A) or ii (type O).", "hint": "List what each parent can possibly contribute, then combine the possibilities."}, {"id": "sds93001", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Motion — Speed", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A car travels 150 km in 2.5 hours. What is its average speed?", "options": ["50 km/h", "60 km/h", "65 km/h", "75 km/h"], "answer": 1, "exp": "Step 1: Speed = distance ÷ time. Step 2: 150 ÷ 2.5 = 60 km/h.", "hint": "Divide the total distance by the total time."}, {"id": "sds93002", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Motion — Acceleration", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A cyclist accelerates from 5 m/s to 20 m/s over 3 seconds. What is their acceleration?", "options": ["3 m/s²", "5 m/s²", "8.3 m/s²", "15 m/s²"], "answer": 1, "exp": "Step 1: Acceleration = (final velocity − initial velocity) ÷ time. Step 2: (20−5) ÷ 3 = 5 m/s².", "hint": "Subtract the initial velocity from the final velocity, then divide by the time taken."}, {"id": "sds93003", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Motion — Graphs", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "On a speed-time graph, what does the area under the graph represent?", "options": ["acceleration", "distance travelled", "force applied", "mass of the object"], "answer": 1, "exp": "The area under a speed-time graph represents the total distance travelled during that time period.", "hint": "Think about what physical quantity you get when you multiply speed by time."}, {"id": "sds93004", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Motion — Graphs", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "On a speed-time graph, what does the gradient (slope) of the line represent?", "options": ["distance travelled", "total time taken", "acceleration", "the object's mass"], "answer": 2, "exp": "The gradient of a speed-time graph represents acceleration — how quickly the speed is changing over time.", "hint": "Think about what a steep upward slope tells you about how quickly speed is increasing."}, {"id": "sds93005", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Motion — Concepts", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "What is the difference between speed and velocity?", "options": ["they mean exactly the same thing", "velocity includes direction, while speed does not", "speed includes direction, while velocity does not", "velocity can only be measured for objects moving in a circle"], "answer": 1, "exp": "Velocity is speed in a specified direction, making it a vector quantity, while speed alone (a scalar) does not include direction.", "hint": "Think about which of these two terms specifically includes information about direction."}, {"id": "sds93006", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Momentum", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A 5 kg object moves at 4 m/s. What is its momentum?", "options": ["1.25 kg·m/s", "9 kg·m/s", "20 kg·m/s", "45 kg·m/s"], "answer": 2, "exp": "Step 1: Momentum = mass × velocity. Step 2: 5 × 4 = 20 kg·m/s.", "hint": "Multiply the object's mass by its velocity."}, {"id": "sds93007", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Newton's Second Law", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A net force of 30 N is applied to a 10 kg object. What is its acceleration?", "options": ["0.3 m/s²", "3 m/s²", "30 m/s²", "300 m/s²"], "answer": 1, "exp": "Step 1: Newton's second law: Force = mass × acceleration, so acceleration = force ÷ mass. Step 2: 30 ÷ 10 = 3 m/s².", "hint": "Rearrange Newton's second law (F = ma) to solve for acceleration."}, {"id": "sds93008", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Newton's Second Law", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "What net force would be needed to accelerate a 10 kg object at 3 m/s²?", "options": ["3.3 N", "7 N", "13 N", "30 N"], "answer": 3, "exp": "Step 1: Force = mass × acceleration. Step 2: 10 × 3 = 30 N.", "hint": "Use Newton's second law: Force = mass × acceleration."}, {"id": "sds93009", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Weight", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A 5 kg object has a weight of approximately how many newtons, using g ≈ 9.8 m/s²?", "options": ["5 N", "9.8 N", "49 N", "58.8 N"], "answer": 2, "exp": "Step 1: Weight = mass × gravitational acceleration. Step 2: 5 × 9.8 = 49 N.", "hint": "Multiply the object's mass by the acceleration due to gravity."}, {"id": "sds93010", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Energy — Kinetic Energy", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A 2 kg object moves at 6 m/s. What is its kinetic energy?", "options": ["12 J", "24 J", "36 J", "72 J"], "answer": 2, "exp": "Step 1: Kinetic energy = 0.5 × mass × velocity². Step 2: 0.5 × 2 × 6² = 0.5 × 2 × 36 = 36 J.", "hint": "Use the formula: kinetic energy = half × mass × velocity squared."}, {"id": "sds93011", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Gravity", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "Which best explains why a heavier object doesn't necessarily fall faster than a lighter object in the absence of air resistance?", "options": ["heavier objects always experience more friction", "both experience the same gravitational acceleration, since acceleration due to gravity does not depend on mass", "gravity does not act on heavier objects at all", "this only applies on other planets, not Earth"], "answer": 1, "exp": "In the absence of air resistance, all objects experience the same gravitational acceleration regardless of mass, which is why a heavy and light object would fall at the same rate.", "hint": "Think about why mass cancels out when calculating gravitational acceleration."}, {"id": "sds93012", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Newton's Laws", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "What is Newton's first law of motion sometimes called?", "options": ["the law of momentum", "the law of inertia", "the law of universal gravitation", "the law of conservation of energy"], "answer": 1, "exp": "Newton's first law is often called the law of inertia, describing how objects resist changes to their state of motion unless acted on by an unbalanced force.", "hint": "This law describes an object's natural tendency to keep doing what it's already doing."}, {"id": "sds93013", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Energy — Conservation", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "According to the law of conservation of energy, what happens to the total energy in a closed system?", "options": ["it increases over time", "it decreases over time", "it remains constant, though it may change form", "it disappears completely eventually"], "answer": 2, "exp": "The law of conservation of energy states that energy cannot be created or destroyed in a closed system — it can only change form (such as from kinetic to potential energy).", "hint": "Think about energy changing form, rather than disappearing or being created from nothing."}, {"id": "sds93014", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Motion — Speed", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A car travels 300 km over a 5-hour trip, including rest stops. What is its average speed for the whole trip?", "options": ["50 km/h", "60 km/h", "65 km/h", "75 km/h"], "answer": 1, "exp": "Step 1: Average speed = total distance ÷ total time. Step 2: 300 ÷ 5 = 60 km/h.", "hint": "Divide the total distance travelled by the total time taken, including any stops."}, {"id": "sds93015", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Motion — Concepts", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A ball is thrown upward and eventually falls back down. At the very highest point of its path, what is its velocity?", "options": ["at its maximum value", "zero, momentarily, before it starts falling", "negative and increasing", "impossible to determine"], "answer": 1, "exp": "At the highest point of its path, the ball's velocity is momentarily zero, just before gravity causes it to begin accelerating downward again.", "hint": "Think about the exact instant the ball stops moving upward, just before it starts moving downward."}, {"id": "sds93016", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Newton's Second Law", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "Which of these correctly describes the relationship between force, mass, and acceleration, according to Newton's second law?", "options": ["F = m + a", "F = m ÷ a", "F = m × a", "F = m − a"], "answer": 2, "exp": "Newton's second law states that Force equals mass multiplied by acceleration (F = ma).", "hint": "Remember the standard formula relating these three quantities."}, {"id": "sds93017", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Air Resistance", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A skydiver reaches 'terminal velocity'. What does this mean?", "options": ["they have stopped moving completely", "their downward speed has reached a constant value, where air resistance balances gravity", "they are accelerating faster than ever", "terminal velocity only applies to objects in a vacuum"], "answer": 1, "exp": "Terminal velocity occurs when air resistance increases enough to exactly balance the force of gravity, resulting in a constant downward speed (zero net acceleration).", "hint": "Think about when the upward force of air resistance becomes equal to the downward force of gravity."}, {"id": "sds93018", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Motion — Acceleration", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A 1000 kg car decelerates from 20 m/s to 0 m/s in 4 seconds during braking. What is its deceleration?", "options": ["2.5 m/s²", "5 m/s²", "20 m/s²", "80 m/s²"], "answer": 1, "exp": "Step 1: Acceleration = (final velocity − initial velocity) ÷ time = (0−20) ÷ 4. Step 2: This gives -5 m/s², meaning a deceleration of 5 m/s².", "hint": "Subtract the initial velocity from the final velocity, then divide by time — a negative result indicates deceleration."}, {"id": "sds93019", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Energy — Potential Energy", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "Which best describes gravitational potential energy?", "options": ["energy due to an object's motion", "energy stored due to an object's height above a reference point", "energy released as sound", "energy stored in a stretched spring only"], "answer": 1, "exp": "Gravitational potential energy is stored energy due to an object's height above a reference point (like the ground), which can convert into kinetic energy if released.", "hint": "Think about the energy an object has simply due to its position above the ground."}, {"id": "sds93020", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Energy — Kinetic Energy", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A roller coaster car has a mass of 500 kg and reaches a maximum speed of 20 m/s at the bottom of its first hill. What is its kinetic energy at that point?", "options": ["5,000 J", "10,000 J", "100,000 J", "200,000 J"], "answer": 2, "exp": "Step 1: Kinetic energy = 0.5 × mass × velocity². Step 2: 0.5 × 500 × 20² = 0.5 × 500 × 400 = 100,000 J.", "hint": "Use the formula: kinetic energy = half × mass × velocity squared."}, {"id": "sds93021", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Safety Applications", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "Why does a seatbelt help protect passengers during a sudden car stop, in terms of force and time?", "options": ["it eliminates all force acting on the passenger", "it extends the time over which the passenger decelerates, reducing the force experienced", "it increases the speed of the collision", "seatbelts have no measurable effect on force or time"], "answer": 1, "exp": "A seatbelt extends the time over which a passenger decelerates during a collision. Since force and time are inversely related for a given change in momentum, this reduces the force experienced by the passenger.", "hint": "Think about how spreading a sudden stop over a slightly longer time can reduce the force involved."}, {"id": "sds93022", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Gravity", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "Two objects of different mass are dropped from the same height in a vacuum (no air resistance). Which best describes what happens?", "options": ["the heavier object lands first", "the lighter object lands first", "both objects land at the same time, since gravitational acceleration is independent of mass", "neither object will fall at all in a vacuum"], "answer": 2, "exp": "In a vacuum, both objects experience the same gravitational acceleration regardless of their mass, so they land at the same time when dropped from the same height.", "hint": "Think about why mass doesn't affect the rate of free-fall acceleration, once air resistance is removed."}, {"id": "sds93023", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Forces — Units", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "What unit is typically used to measure force?", "options": ["joule", "newton", "watt", "kilogram"], "answer": 1, "exp": "Force is measured in newtons (N).", "hint": "This unit shares its name with the scientist known for his laws of motion."}, {"id": "sds93024", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Energy — Units", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "What unit is typically used to measure energy?", "options": ["newton", "joule", "metre per second", "kilogram"], "answer": 1, "exp": "Energy is measured in joules (J).", "hint": "This is the same unit used to measure 'work done' in physics."}, {"id": "sds93025", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Motion — Speed", "difficulty": "hard", "style": "standard", "paper": "G9-S3", "q": "A cyclist travels at a constant 8 m/s for 15 seconds. How far do they travel in this time?", "options": ["23 m", "60 m", "120 m", "180 m"], "answer": 2, "exp": "Step 1: Distance = speed × time. Step 2: 8 × 15 = 120 m.", "hint": "Multiply the constant speed by the time travelled."}, {"id": "sds94001", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Nervous System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "What is the main function of the nervous system?", "options": ["to produce hormones only", "to transmit electrical signals throughout the body, allowing rapid communication and response", "to digest food", "to pump blood around the body"], "answer": 1, "exp": "The nervous system transmits electrical signals (nerve impulses) throughout the body, allowing rapid communication between the brain, spinal cord, and the rest of the body.", "hint": "Think about the system responsible for quick reactions, like pulling your hand away from something hot."}, {"id": "sds94002", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Nervous System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which part of the nervous system is described as the 'control centre' of the body?", "options": ["the spinal cord", "the brain", "peripheral nerves only", "the skin"], "answer": 1, "exp": "The brain acts as the body's main control centre, processing information and coordinating responses throughout the nervous system.", "hint": "Think about the organ responsible for thinking, decision-making, and coordinating the body's responses."}, {"id": "sds94003", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Nervous System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "What is a 'neuron'?", "options": ["a type of muscle cell", "a specialised cell that transmits electrical signals in the nervous system", "a hormone-producing gland", "a type of bone cell"], "answer": 1, "exp": "A neuron is a specialised cell designed to transmit electrical signals (nerve impulses) throughout the nervous system.", "hint": "Think about the specific type of cell that makes up nerves and the brain."}, {"id": "sds94004", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Nervous System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "What is a 'reflex action'?", "options": ["a slow, carefully considered response", "a rapid, automatic response to a stimulus, often bypassing conscious thought", "a response that only occurs during sleep", "a response that requires extensive prior learning"], "answer": 1, "exp": "A reflex action is a rapid, automatic response to a stimulus (like touching something hot), often occurring before the brain has even consciously processed the situation.", "hint": "Think about an extremely fast, involuntary reaction, like blinking or pulling away from pain."}, {"id": "sds94005", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Endocrine System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "What is the main function of the endocrine system?", "options": ["to transmit electrical signals rapidly", "to produce and release hormones that regulate body processes over a longer timeframe than the nervous system", "to filter waste from the blood", "to absorb nutrients from food"], "answer": 1, "exp": "The endocrine system produces hormones, chemical messengers released into the bloodstream that regulate body processes, generally acting over a longer timeframe than the rapid nervous system.", "hint": "Think about the system that uses chemical messengers (hormones), rather than electrical signals."}, {"id": "sds94006", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Endocrine System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "What is a 'hormone'?", "options": ["a type of nerve cell", "a chemical messenger released into the bloodstream that affects target cells or organs", "a structure found only in plants", "a type of bone tissue"], "answer": 1, "exp": "A hormone is a chemical messenger, produced by glands and released into the bloodstream, that travels to and affects specific target cells or organs.", "hint": "Think about a chemical 'message' travelling through the blood to reach a specific target."}, {"id": "sds94007", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Endocrine System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which gland produces insulin, a hormone that helps regulate blood sugar levels?", "options": ["the thyroid gland", "the pancreas", "the pituitary gland", "the adrenal gland"], "answer": 1, "exp": "The pancreas produces insulin, a hormone that helps regulate blood sugar (glucose) levels in the body.", "hint": "Think about the gland associated with diabetes and blood sugar regulation."}, {"id": "sds94008", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Integration", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which best describes the difference between the nervous system's and the endocrine system's typical response speed?", "options": ["both systems respond at exactly the same speed", "the nervous system typically responds faster (using electrical signals), while the endocrine system typically responds more slowly (using hormones in the blood)", "the endocrine system always responds faster than the nervous system", "neither system has any measurable response speed"], "answer": 1, "exp": "The nervous system typically responds very quickly using electrical signals, while the endocrine system typically acts more slowly, since hormones must travel through the bloodstream to reach their target.", "hint": "Think about the difference between an electrical signal travelling along a nerve versus a hormone travelling through blood."}, {"id": "sds94009", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "A scientist hypothesises that caffeine increases heart rate. Which of these would be the most appropriate independent variable for testing this hypothesis?", "options": ["the participant's age", "the amount of caffeine consumed", "the time of day", "the participant's height"], "answer": 1, "exp": "To test this specific hypothesis, the independent variable (the one deliberately changed) should be the amount of caffeine consumed, directly relating to the hypothesis being tested.", "hint": "Look for the variable that directly matches what the hypothesis claims to be affecting heart rate."}, {"id": "sds94010", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "In the same investigation, what would be the most appropriate dependent variable?", "options": ["the amount of caffeine given", "the participant's heart rate", "the room temperature", "the brand of caffeine used"], "answer": 1, "exp": "The dependent variable should be heart rate, since this is what is being measured as a possible result of the caffeine consumed.", "hint": "Look for the variable being measured, which is expected to change depending on caffeine intake."}, {"id": "sds94011", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Why might this caffeine investigation include a control group given a placebo (a substance with no caffeine) instead of nothing at all?", "options": ["to account for any psychological effect of simply consuming a drink, regardless of its actual contents", "placebos have no real scientific purpose", "to make the experiment more expensive", "to ensure all participants get exactly the same amount of caffeine"], "answer": 0, "exp": "A placebo helps account for any psychological or behavioural effect of simply consuming a drink, ensuring that any change in heart rate can be more confidently attributed specifically to the caffeine itself.", "hint": "Think about isolating the effect of caffeine itself, separate from the simple act of drinking something."}, {"id": "sds94012", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which best describes a 'double-blind' study?", "options": ["neither the participants nor the researchers analysing results know who received the real treatment versus the placebo, until after data collection", "only the participants are aware of the treatment they received", "only the researchers know the treatment groups", "double-blind studies are never used in real scientific research"], "answer": 0, "exp": "In a double-blind study, neither the participants nor the researchers analysing results know who received the real treatment versus the placebo, reducing the risk of bias affecting the results.", "hint": "Think about why hiding this information from BOTH groups (not just participants) could reduce bias."}, {"id": "sds94013", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Why is a large sample size generally preferred in a scientific investigation, compared to a very small one?", "options": ["a large sample size has no real scientific benefit", "a large sample size generally improves reliability, reducing the impact of unusual individual results on the overall conclusion", "a large sample size is always more expensive with no benefit", "sample size has no connection to the reliability of results"], "answer": 1, "exp": "A larger sample size generally improves the reliability of results, reducing the impact that one or two unusual individual responses might have on the overall conclusion.", "hint": "Think about how a few unusual individual results might skew a very small sample more than a large one."}, {"id": "sds94014", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Nervous System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which best describes the role of the spinal cord in the nervous system?", "options": ["it has no real function in the nervous system", "it acts as a major pathway for nerve signals travelling between the brain and the rest of the body, and can also process some reflexes directly", "it produces hormones exclusively", "it filters waste from the blood"], "answer": 1, "exp": "The spinal cord acts as a major pathway carrying nerve signals between the brain and the rest of the body, and can also process some reflex actions directly, without needing to involve the brain.", "hint": "Think about the structure connecting the brain to the rest of the nervous system, running down the back."}, {"id": "sds94015", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which best explains why scientists often publish their methods in detail alongside their results?", "options": ["to allow other scientists to repeat the investigation and verify the findings", "publishing methods serves no real scientific purpose", "to make the research paper longer", "methods are never actually published in real research"], "answer": 0, "exp": "Publishing detailed methods allows other scientists to repeat the investigation, helping to verify whether the findings are reliable and not due to a flawed or unrepeatable process.", "hint": "Think about why other scientists would need to know exactly how an investigation was carried out."}, {"id": "sds94016", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Endocrine System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which best describes adrenaline's main effect on the body during a 'fight or flight' response?", "options": ["it slows the heart rate and induces sleepiness", "it increases heart rate, blood flow to muscles, and alertness, preparing the body for rapid action", "it has no measurable physical effect", "it only affects digestion"], "answer": 1, "exp": "Adrenaline increases heart rate, redirects blood flow to muscles, and increases alertness, preparing the body for rapid physical action in response to a perceived threat.", "hint": "Think about the physical changes you might notice in a sudden, stressful, or exciting situation."}, {"id": "sds94017", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "A scientist wants to test the effect of exercise on heart rate but only tests one participant. What is the main limitation of this approach?", "options": ["there is no real limitation with this approach", "results from a single participant may not be representative of people generally, limiting how confidently the findings can be generalised", "testing only one person is always the best scientific approach", "single-participant studies are never used in real research"], "answer": 1, "exp": "Results from a single participant may reflect that individual's unique characteristics rather than a generalisable pattern, limiting how confidently the findings can be applied to people more broadly.", "hint": "Think about whether one person's results can fairly represent everyone, given individual variation."}, {"id": "sds94018", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Nervous System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which best describes a 'stimulus' in the context of the nervous system?", "options": ["a chemical messenger released into the blood", "any change in the environment that triggers a response in an organism", "a type of nerve cell", "a part of the brain only"], "answer": 1, "exp": "A stimulus is any change in the environment (such as heat, light, or sound) that triggers a response in an organism's nervous system.", "hint": "Think about the 'trigger' that causes a nervous system response in the first place."}, {"id": "sds94019", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Integration", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which best describes 'homeostasis'?", "options": ["a single, one-time bodily reaction", "the body's ability to maintain a stable internal environment, despite changes in external conditions", "a process that only occurs in plants", "a type of disease"], "answer": 1, "exp": "Homeostasis describes the body's ongoing ability to maintain a stable internal environment (such as body temperature or blood sugar levels), despite changes in external conditions.", "hint": "Think about the body constantly working to keep internal conditions steady, like temperature regulation."}, {"id": "sds94020", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Integration", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Why might both the nervous and endocrine systems work together to regulate blood sugar levels?", "options": ["the two systems never interact with each other", "combining rapid nervous signals with longer-lasting hormonal responses allows for both quick adjustments and sustained regulation", "only the endocrine system has any role in blood sugar regulation", "blood sugar regulation has no connection to either system"], "answer": 1, "exp": "Combining the nervous system's rapid signalling with the endocrine system's longer-lasting hormonal effects allows the body to make both quick initial adjustments and sustain longer-term regulation of blood sugar levels.", "hint": "Think about the benefit of having both a fast-acting system and a slower, longer-lasting system working together."}, {"id": "sds94021", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "A study finds a correlation between students who eat breakfast and higher test scores. Why should a scientist be cautious about concluding that eating breakfast directly causes higher test scores?", "options": ["correlation always proves causation, so no caution is needed", "other factors (such as overall family routine or socioeconomic factors) could independently explain both variables", "this kind of study can never reveal anything useful", "breakfast has been scientifically proven to have no effect on anything"], "answer": 1, "exp": "Other factors, such as overall family routine, sleep habits, or socioeconomic circumstances, could independently influence both breakfast habits and test performance, without breakfast directly causing the improved scores.", "hint": "Think about other underlying factors that could explain both the breakfast habit and the test scores, without one directly causing the other."}, {"id": "sds94022", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which best describes the purpose of a 'pilot study' before conducting a larger investigation?", "options": ["pilot studies serve no real scientific purpose", "a small-scale trial run, used to identify potential problems with the method before committing to a larger, more costly investigation", "a pilot study always replaces the need for a full investigation", "pilot studies are only used in aviation research"], "answer": 1, "exp": "A pilot study is a small-scale trial run, allowing researchers to identify and fix potential problems with their method before committing time and resources to a larger, full-scale investigation.", "hint": "Think about testing your method on a small scale first, to catch any problems early."}, {"id": "sds94023", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Body Systems — Endocrine System", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which gland is sometimes referred to as the 'master gland', since it controls the activity of several other endocrine glands?", "options": ["the thyroid gland", "the pituitary gland", "the pancreas", "the adrenal gland"], "answer": 1, "exp": "The pituitary gland is often called the 'master gland' because it produces hormones that regulate the activity of several other endocrine glands throughout the body.", "hint": "Think about the gland that essentially manages and coordinates several other hormone-producing glands."}, {"id": "sds94024", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Why is it considered good scientific practice to disclose any potential conflicts of interest (such as funding sources) when publishing research?", "options": ["disclosure has no real importance in scientific research", "it allows others to consider whether funding sources might have influenced the study's design or conclusions", "conflicts of interest are not possible in scientific research", "disclosure is only required in unrelated fields, not science"], "answer": 1, "exp": "Disclosing potential conflicts of interest, such as funding sources, allows other scientists and the public to consider whether these factors might have influenced the study's design, execution, or conclusions.", "hint": "Think about why knowing who funded a study might be relevant when evaluating its conclusions."}, {"id": "sds94025", "state": "AU", "section": "sec_science", "grade": "9", "topic": "Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G9-S4", "q": "Which best describes why peer review is an important part of the scientific process before research is published?", "options": ["peer review guarantees a study is completely free of any errors", "independent experts examine the study's methods and conclusions, helping catch potential errors or weaknesses before publication", "peer review is a purely formal step with no real scrutiny involved", "peer review is unique to medical research and not used elsewhere"], "answer": 1, "exp": "Peer review involves independent experts examining a study's methods, data, and conclusions before publication, helping to catch potential errors, weaknesses, or unsupported claims.", "hint": "Think about why having other qualified experts check a study's work, before it's published, adds a layer of quality control."}, {"id": "sds101001", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which type of reaction occurs when a metal reacts with oxygen to form a metal oxide?", "options": ["a synthesis (combination) reaction", "a decomposition reaction", "a displacement reaction", "a precipitation reaction"], "answer": 0, "exp": "This is a synthesis (combination) reaction, where two substances (a metal and oxygen) combine to form a single new product (a metal oxide).", "hint": "Think about two substances combining together to form one single new substance."}, {"id": "sds101002", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which type of reaction occurs when calcium carbonate breaks down into calcium oxide and carbon dioxide when heated?", "options": ["a synthesis reaction", "a decomposition reaction", "a combustion reaction", "a neutralisation reaction"], "answer": 1, "exp": "This is a decomposition reaction, where a single compound breaks down into two or more simpler substances.", "hint": "Think about ONE substance breaking apart into multiple simpler substances."}, {"id": "sds101003", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which type of reaction occurs when zinc displaces copper from a copper sulfate solution?", "options": ["a synthesis reaction", "a decomposition reaction", "a displacement reaction", "a combustion reaction"], "answer": 2, "exp": "This is a displacement reaction, where a more reactive element (zinc) displaces a less reactive element (copper) from a compound.", "hint": "Think about one element 'pushing out' another element from a compound it was part of."}, {"id": "sds101004", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which type of reaction occurs between an acid and a base, typically producing a salt and water?", "options": ["a combustion reaction", "a neutralisation reaction", "a decomposition reaction", "a synthesis reaction"], "answer": 1, "exp": "This is a neutralisation reaction, where an acid reacts with a base to produce a salt and water, neutralising the acidic and basic properties.", "hint": "Think about the specific reaction type that occurs when an acid and a base 'cancel out' each other's properties."}, {"id": "sds101005", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Stoichiometry — Concepts", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "What is 'molar mass'?", "options": ["the mass of a single atom", "the mass of one mole of a substance, usually measured in grams per mole", "the volume of a substance", "the temperature at which a substance melts"], "answer": 1, "exp": "Molar mass is the mass of one mole (6.02 × 10²³ particles) of a substance, typically measured in grams per mole (g/mol).", "hint": "Think about the mass associated with a standard chemistry counting unit — the mole."}, {"id": "sds101006", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Stoichiometry — Mole Calculations", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Water (H₂O) has a molar mass of approximately 18 g/mol. How many moles are in 36 g of water?", "options": ["0.5 moles", "1 mole", "2 moles", "18 moles"], "answer": 2, "exp": "Step 1: Moles = mass ÷ molar mass. Step 2: 36 ÷ 18 = 2 moles.", "hint": "Divide the given mass by the molar mass to find the number of moles."}, {"id": "sds101007", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Stoichiometry — Mole Calculations", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Carbon dioxide (CO₂) has a molar mass of approximately 44 g/mol. How many moles are in 22 g of CO₂?", "options": ["0.5 moles", "1 mole", "2 moles", "22 moles"], "answer": 0, "exp": "Step 1: Moles = mass ÷ molar mass. Step 2: 22 ÷ 44 = 0.5 moles.", "hint": "Divide the given mass by the molar mass to find the number of moles."}, {"id": "sds101008", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Stoichiometry — Percentage Yield", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "A chemical reaction has a theoretical yield of 10 g, but the actual yield obtained is 8.5 g. What is the percentage yield?", "options": ["75%", "80%", "85%", "90%"], "answer": 2, "exp": "Step 1: Percentage yield = (actual yield ÷ theoretical yield) × 100. Step 2: (8.5 ÷ 10) × 100 = 85%.", "hint": "Divide the actual yield by the theoretical yield, then convert to a percentage."}, {"id": "sds101009", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Stoichiometry — Percentage Yield", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Why is the actual yield of a chemical reaction often less than the theoretical yield?", "options": ["chemical reactions always produce more product than predicted", "factors like incomplete reactions, side reactions, or loss during purification often reduce the actual amount of product obtained", "theoretical yield calculations are always inaccurate", "actual yield is always exactly equal to theoretical yield in real experiments"], "answer": 1, "exp": "Actual yield is often lower than theoretical yield due to factors like incomplete reactions, unwanted side reactions, or product lost during purification and handling.", "hint": "Think about practical, real-world factors that might prevent a reaction from producing exactly the predicted amount."}, {"id": "sds101010", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Balancing Equations", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "In a balanced chemical equation, what does the law of conservation of mass require?", "options": ["the same number of each type of atom must appear on both sides of the equation", "the mass of products is always greater than reactants", "atoms can be created or destroyed during reactions", "balancing equations is optional in chemistry"], "answer": 0, "exp": "A balanced chemical equation requires the same number of each type of atom on both the reactant and product sides, reflecting the law of conservation of mass.", "hint": "Think about what needs to match exactly on both sides of a correctly balanced equation."}, {"id": "sds101011", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Balancing Equations", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Balance this equation: __ H₂ + __ O₂ → __ H₂O", "options": ["1 H₂ + 1 O₂ → 1 H₂O", "2 H₂ + 1 O₂ → 2 H₂O", "2 H₂ + 2 O₂ → 2 H₂O", "1 H₂ + 2 O₂ → 1 H₂O"], "answer": 1, "exp": "The balanced equation is 2H₂ + O₂ → 2H₂O, giving 4 hydrogen atoms and 2 oxygen atoms on both sides.", "hint": "Count the hydrogen and oxygen atoms on each side, adjusting the coefficients until they match."}, {"id": "sds101012", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Energy", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which of these is evidence that a chemical reaction is exothermic?", "options": ["the surrounding temperature decreases", "the surrounding temperature increases, as heat is released into the surroundings", "no temperature change occurs at all", "the reaction absorbs energy from its surroundings"], "answer": 1, "exp": "An exothermic reaction releases heat energy into its surroundings, causing the surrounding temperature to increase.", "hint": "Think about the prefix 'exo-', meaning 'outward' or 'releasing'."}, {"id": "sds101013", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Energy", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which of these is evidence that a chemical reaction is endothermic?", "options": ["the surrounding temperature increases", "the surrounding temperature decreases, as heat is absorbed from the surroundings", "the reaction always produces a gas", "endothermic reactions never actually occur"], "answer": 1, "exp": "An endothermic reaction absorbs heat energy from its surroundings, causing the surrounding temperature to decrease.", "hint": "Think about the prefix 'endo-', meaning 'inward' or 'absorbing'."}, {"id": "sds101014", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Catalysts", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "What is a 'catalyst' in a chemical reaction?", "options": ["a substance that slows down a reaction", "a substance that speeds up a reaction without being permanently used up itself", "a type of acid only", "a substance that always changes colour during a reaction"], "answer": 1, "exp": "A catalyst speeds up a chemical reaction by lowering the energy required, without being permanently consumed or changed by the reaction itself.", "hint": "Think about a substance that helps a reaction go faster, but isn't actually used up in the process."}, {"id": "sds101015", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Acids and Bases", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which best describes the pH scale used to measure acidity and alkalinity?", "options": ["it ranges from 0 (most acidic) to 14 (most alkaline), with 7 being neutral", "it ranges from 0 to 100, with 50 being neutral", "it only applies to liquids, never to solids or gases", "pH has no connection to acidity or alkalinity"], "answer": 0, "exp": "The pH scale ranges from 0 (most acidic) to 14 (most alkaline/basic), with 7 representing a neutral substance, such as pure water.", "hint": "Remember the standard numerical range of this scale, and which value represents neutral."}, {"id": "sds101016", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Acids and Bases", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which of these substances would most likely have a pH well below 7?", "options": ["pure water", "lemon juice", "sodium hydroxide solution (a strong base)", "baking soda solution"], "answer": 1, "exp": "Lemon juice is acidic, due to citric acid, giving it a pH well below 7 (typically around 2).", "hint": "Think about which of these substances is known for its sour, acidic taste."}, {"id": "sds101017", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Stoichiometry — Mole Calculations", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "4 g of hydrogen gas (H₂, molar mass ≈ 2 g/mol) reacts completely with oxygen. How many moles of hydrogen gas are present?", "options": ["0.5 moles", "1 mole", "2 moles", "4 moles"], "answer": 2, "exp": "Step 1: Moles = mass ÷ molar mass. Step 2: 4 ÷ 2 = 2 moles.", "hint": "Divide the given mass by the molar mass to find the number of moles."}, {"id": "sds101018", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which of these would most likely indicate that a precipitation reaction has occurred when two solutions are mixed?", "options": ["the temperature stays exactly the same", "an insoluble solid forms and settles out or clouds the mixture", "the mixture becomes completely transparent with no visible change", "a gas is released with a strong odour"], "answer": 1, "exp": "A precipitation reaction produces an insoluble solid (a precipitate), which becomes visible as cloudiness or solid particles settling in the mixture.", "hint": "Think about the visible sign you'd notice if an insoluble solid suddenly formed within a liquid mixture."}, {"id": "sds101019", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which best describes combustion as a type of chemical reaction?", "options": ["a substance reacting with oxygen, typically releasing heat and light energy", "a substance breaking down without any oxygen involved", "two solids being physically mixed together with no chemical change", "a reaction that only occurs underwater"], "answer": 0, "exp": "Combustion involves a substance reacting with oxygen, typically releasing heat and light energy, as seen when fuels burn.", "hint": "Think about the reaction type involved in burning, such as wood or fuel."}, {"id": "sds101020", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Stoichiometry — Mole Calculations", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "24 g of magnesium (molar mass ≈ 24 g/mol) reacts with oxygen. How many moles of magnesium are present?", "options": ["0.5 moles", "1 mole", "2 moles", "24 moles"], "answer": 1, "exp": "Step 1: Moles = mass ÷ molar mass. Step 2: 24 ÷ 24 = 1 mole.", "hint": "Divide the given mass by the molar mass to find the number of moles."}, {"id": "sds101021", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Stoichiometry — Concepts", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which best explains why chemists balance chemical equations before performing stoichiometric calculations?", "options": ["balancing has no real purpose in calculations", "a balanced equation correctly shows the ratio of moles of reactants to products, which is essential for accurate calculations", "balancing equations is purely a cosmetic, presentational step", "unbalanced equations are always more accurate"], "answer": 1, "exp": "A balanced equation correctly shows the mole ratio between reactants and products, which is essential information for performing accurate stoichiometric calculations.", "hint": "Think about why knowing the correct ratio of reactants to products matters for calculating quantities."}, {"id": "sds101022", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which of these reactions is best classified as a synthesis reaction?", "options": ["2H₂ + O₂ → 2H₂O", "2H₂O₂ → 2H₂O + O₂", "Zn + CuSO₄ → ZnSO₄ + Cu", "HCl + NaOH → NaCl + H₂O"], "answer": 0, "exp": "2H₂ + O₂ → 2H₂O is a synthesis reaction, since two reactants (hydrogen and oxygen) combine to form a single new product (water).", "hint": "Look for the equation where two separate reactants combine into a single product."}, {"id": "sds101023", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which of these reactions is best classified as a decomposition reaction?", "options": ["2H₂ + O₂ → 2H₂O", "2H₂O₂ → 2H₂O + O₂", "Zn + CuSO₄ → ZnSO₄ + Cu", "HCl + NaOH → NaCl + H₂O"], "answer": 1, "exp": "2H₂O₂ → 2H₂O + O₂ is a decomposition reaction, since a single reactant (hydrogen peroxide) breaks down into two simpler products.", "hint": "Look for the equation where a single reactant breaks down into multiple simpler products."}, {"id": "sds101024", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Stoichiometry — Gas Volumes", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which best describes the relationship between the number of moles of a gas and its volume at a constant temperature and pressure?", "options": ["they have no relationship at all", "the volume is directly proportional to the number of moles (more moles means a larger volume)", "the volume is inversely proportional to the number of moles", "the volume always stays exactly the same regardless of moles"], "answer": 1, "exp": "At a constant temperature and pressure, the volume of a gas is directly proportional to the number of moles present — more moles of gas occupy a larger volume.", "hint": "Think about what happens to the volume of a gas as you add more of it, keeping conditions constant."}, {"id": "sds101025", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Chemical Reactions — Concepts", "difficulty": "hard", "style": "standard", "paper": "G10-S1", "q": "Which of these would most likely indicate that a chemical reaction has reached completion (no further visible change)?", "options": ["bubbling or fizzing continues indefinitely", "the colour, temperature, and any gas production stop changing, remaining constant", "the mixture becomes more reactive over time", "this can never actually be determined"], "answer": 1, "exp": "A reaction reaching completion is typically indicated by the colour, temperature, and any gas production becoming constant, with no further observable changes occurring.", "hint": "Think about what you would observe (or stop observing) once a reaction has fully finished."}, {"id": "sds102001", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "What is the main mechanism Charles Darwin proposed to explain how species change over time?", "options": ["selective breeding by humans only", "natural selection, where individuals with advantageous traits survive and reproduce more successfully", "spontaneous generation", "the inheritance of acquired characteristics from a single generation"], "answer": 1, "exp": "Darwin proposed natural selection as the main mechanism of evolution, where individuals with traits better suited to their environment survive and reproduce more successfully, passing those traits on.", "hint": "Think about the process where environmental pressures favour certain traits over others, over many generations."}, {"id": "sds102002", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "What is required for natural selection to act on a population?", "options": ["all individuals must be genetically identical", "there must be heritable variation among individuals within the population", "the population must remain completely unchanged over time", "natural selection requires no variation at all"], "answer": 1, "exp": "Natural selection requires heritable variation among individuals — without genetic differences that can be passed on, there is nothing for selection to act upon.", "hint": "Think about what's needed for some individuals to have an advantage over others in survival and reproduction."}, {"id": "sds102003", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "What is 'adaptation' in the context of evolution?", "options": ["a deliberate choice an organism makes to change its environment", "an inherited trait that improves an organism's chances of survival and reproduction in its environment", "a type of disease affecting a population", "a trait that has no connection to survival"], "answer": 1, "exp": "An adaptation is an inherited trait that improves an organism's chances of survival and reproduction within its particular environment.", "hint": "Think about an inherited feature that specifically helps an organism survive and reproduce where it lives."}, {"id": "sds102004", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "What is meant by 'survival of the fittest' in evolutionary theory?", "options": ["only the physically strongest individuals ever survive", "individuals best suited to their specific environment tend to survive and reproduce more successfully, not necessarily the physically strongest", "all individuals have an exactly equal chance of survival", "this phrase has no real connection to evolution"], "answer": 1, "exp": "\"Survival of the fittest\" refers to individuals best suited (fittest) to their specific environment, which doesn't necessarily mean physically strongest — it could mean better camouflaged, more efficient, or otherwise better adapted.", "hint": "Think about 'fitness' in this context meaning 'well-suited to the environment', not necessarily physical strength."}, {"id": "sds102005", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "What is 'speciation'?", "options": ["the extinction of a species", "the process by which new species evolve, often due to populations becoming isolated and accumulating genetic differences over time", "a single mutation occurring in one individual", "the process of classifying an existing species"], "answer": 1, "exp": "Speciation is the process by which new species evolve, often occurring when populations become geographically or reproductively isolated, accumulating genetic differences over many generations.", "hint": "Think about how one population might eventually split into two distinct species over a long period of time."}, {"id": "sds102006", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best describes 'convergent evolution'?", "options": ["unrelated species independently evolving similar traits due to similar environmental pressures", "two closely related species evolving in completely opposite directions", "a single species evolving very rapidly within one generation", "species evolving without any environmental influence at all"], "answer": 0, "exp": "Convergent evolution occurs when unrelated species independently evolve similar traits because they face similar environmental pressures, such as the streamlined bodies of dolphins and sharks.", "hint": "Think about unrelated species ending up with similar features because they face similar challenges."}, {"id": "sds102007", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution — Evidence", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "What evidence do fossils provide for evolution?", "options": ["fossils provide no useful evidence for evolution", "fossils show how species have changed over long periods of time, including the existence of now-extinct transitional forms", "fossils only ever show identical, unchanging species over time", "fossils can only be found in one specific location on Earth"], "answer": 1, "exp": "Fossils provide a record of how species have changed over long periods of time, including transitional forms that show connections between different groups of organisms.", "hint": "Think about what a record of organisms across many different time periods could reveal about change over time."}, {"id": "sds102008", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution — Evidence", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "How does comparing the DNA of different species provide evidence for evolutionary relationships?", "options": ["DNA comparisons reveal nothing about evolutionary relationships", "species with more similar DNA sequences are generally more closely related evolutionarily, having shared a more recent common ancestor", "all species have identical DNA regardless of relationship", "DNA comparison can only be used on living species, providing no evidence for evolution"], "answer": 1, "exp": "Species with more similar DNA sequences are generally more closely related evolutionarily, suggesting they shared a more recent common ancestor than species with more different DNA.", "hint": "Think about how genetic similarity might relate to how recently two species shared a common ancestor."}, {"id": "sds102009", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "What is an 'ecological niche'?", "options": ["the physical location where an organism lives", "the specific role an organism plays within its ecosystem, including how it obtains resources and interacts with other species", "a type of fossil", "a measurement of population size only"], "answer": 1, "exp": "An ecological niche describes the specific role an organism plays within its ecosystem, including its resource use, habitat preferences, and interactions with other species.", "hint": "Think about the specific 'job' or role an organism has within its ecosystem, not just where it physically lives."}, {"id": "sds102010", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems — Biodiversity", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best describes 'biodiversity'?", "options": ["the total number of organisms in a single species", "the variety of different species and genetic variation within an ecosystem or region", "a measurement of an ecosystem's temperature range", "the total mass of all organisms combined"], "answer": 1, "exp": "Biodiversity refers to the variety of different species and genetic variation present within an ecosystem or region.", "hint": "Think about the overall VARIETY of life, not just the total number of any one type of organism."}, {"id": "sds102011", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems — Biodiversity", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Why is biodiversity generally considered important for ecosystem stability?", "options": ["biodiversity has no real connection to ecosystem stability", "a greater variety of species can make an ecosystem more resilient to disturbances, since the loss of one species is less likely to cause a complete collapse", "ecosystems with only one species are always the most stable", "biodiversity always decreases an ecosystem's overall stability"], "answer": 1, "exp": "A greater variety of species generally makes an ecosystem more resilient to disturbances, since multiple species can often fulfil similar roles, reducing the risk of total ecosystem collapse if one species is lost.", "hint": "Think about why having many different species 'filling similar roles' might protect an ecosystem if one species disappears."}, {"id": "sds102012", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems — Invasive Species", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best describes an 'invasive species'?", "options": ["any new species discovered by scientists", "a non-native species introduced to an ecosystem, which can cause significant ecological or economic harm", "a species that has always lived in a particular ecosystem", "a species that is now extinct"], "answer": 1, "exp": "An invasive species is a non-native species introduced to a new ecosystem, often causing significant ecological harm by outcompeting native species or disrupting existing food webs.", "hint": "Think about a species that doesn't naturally belong in a particular ecosystem, but has been introduced there."}, {"id": "sds102013", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems — Invasive Species", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Why might an invasive predator cause significant ecological damage in a new environment?", "options": ["invasive predators are always weaker than native predators", "native prey species may have no evolved defences against this unfamiliar predator, unlike predators they evolved alongside", "invasive species can never successfully establish themselves", "invasive predators always go extinct immediately"], "answer": 1, "exp": "Native prey species often have no evolved defences against an unfamiliar invasive predator, unlike the defences they may have developed against predators they evolved alongside over a long time.", "hint": "Think about why prey that evolved without ever encountering a particular predator might struggle to defend themselves against it."}, {"id": "sds102014", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution — Co-evolution", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best describes 'co-evolution' between two species, such as a flower and its specific pollinator?", "options": ["two species evolving completely independently with no influence on each other", "two species evolving together over time, each influencing the other's adaptations", "one species evolving while the other remains completely unchanged", "co-evolution only occurs between predator and prey, never between other relationships"], "answer": 1, "exp": "Co-evolution occurs when two species evolve together over time, with adaptations in one species influencing the evolutionary path of the other, such as a flower's shape evolving alongside a specific pollinator's feeding structures.", "hint": "Think about two species shaping each other's evolution over time, through their close ecological relationship."}, {"id": "sds102015", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems — Keystone Species", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "What is a 'keystone species'?", "options": ["the most numerous species in an ecosystem", "a species whose presence has a disproportionately large effect on the structure and stability of its ecosystem, relative to its abundance", "a species that has no real ecological importance", "a species found only in extreme environments"], "answer": 1, "exp": "A keystone species has a disproportionately large effect on its ecosystem's structure and stability, relative to its actual abundance — removing it can cause significant ecological changes.", "hint": "Think about a species whose influence on the ecosystem is much larger than its actual numbers might suggest."}, {"id": "sds102016", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems — Keystone Species", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Why might the removal of a keystone predator from an ecosystem lead to significant, cascading changes?", "options": ["keystone predators have no real ecological influence", "without the predator controlling prey populations, prey numbers can increase dramatically, which can then affect vegetation and other species throughout the food web", "removing any single species always has no effect on an ecosystem", "keystone predators are always replaced immediately by another identical species"], "answer": 1, "exp": "Without a keystone predator controlling prey populations, prey numbers can increase dramatically, which can then significantly affect vegetation and cascade through the rest of the food web.", "hint": "Think about what happens to prey populations, and then to the plants those prey eat, if a top predator disappears."}, {"id": "sds102017", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems — Genetic Diversity", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best describes 'genetic diversity' within a single species' population?", "options": ["genetic diversity refers to the number of different species present", "the variety of different alleles and genetic traits present among individuals of the same species", "genetic diversity has no connection to a species' ability to adapt to change", "all individuals within a species always have identical genetics"], "answer": 1, "exp": "Genetic diversity refers to the variety of different alleles and genetic traits present among individuals within the same species, which can affect a population's ability to adapt to environmental change.", "hint": "Think about variation WITHIN a single species, rather than variation between different species."}, {"id": "sds102018", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems — Genetic Diversity", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Why might low genetic diversity make a species more vulnerable to extinction?", "options": ["genetic diversity has no real connection to extinction risk", "with limited genetic variation, a population may lack the traits needed to adapt to new diseases, environmental changes, or other challenges", "low genetic diversity always guarantees a species' survival", "species with low genetic diversity are always more numerous"], "answer": 1, "exp": "With limited genetic variation, a population may lack individuals with traits suited to surviving new diseases, environmental changes, or other challenges, increasing its vulnerability to extinction.", "hint": "Think about why having more genetic 'options' within a population might help it survive unexpected challenges."}, {"id": "sds102019", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution — Selective Breeding", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "What is 'artificial selection' (selective breeding), and how does it differ from natural selection?", "options": ["they are exactly the same process", "artificial selection involves humans deliberately choosing which organisms breed based on desired traits, rather than the environment naturally selecting for survival advantages", "artificial selection only occurs in plants, never in animals", "artificial selection has no connection to evolutionary principles at all"], "answer": 1, "exp": "Artificial selection involves humans deliberately choosing which organisms breed based on desired traits (such as milk yield or coat colour), rather than the environment naturally selecting for survival advantages.", "hint": "Think about the key difference in WHO or WHAT is doing the 'selecting' — humans, versus the natural environment."}, {"id": "sds102020", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution — Real-World Examples", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best explains why antibiotic resistance in bacteria is considered a real-world example of natural selection in action?", "options": ["bacteria deliberately choose to become resistant", "bacteria with random mutations that happen to provide resistance survive antibiotic treatment and reproduce, passing on this resistance to future generations", "antibiotic resistance has no connection to evolutionary principles", "all bacteria are naturally resistant to antibiotics from birth"], "answer": 1, "exp": "Bacteria with random mutations that happen to provide antibiotic resistance survive treatment and reproduce, passing the resistance gene to future generations — a clear, observable example of natural selection occurring over relatively short timescales.", "hint": "Think about how random genetic variation, combined with a strong selective pressure (antibiotics), could lead to a population becoming more resistant over time."}, {"id": "sds102021", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best describes the concept of 'carrying capacity' in relation to a specific ecosystem?", "options": ["the total weight an ecosystem can physically support", "the maximum population size an ecosystem's resources can sustainably support over time", "a fixed number that applies equally to every ecosystem on Earth", "carrying capacity has no real connection to population size"], "answer": 1, "exp": "Carrying capacity is the maximum population size that an ecosystem's available resources (food, water, space, etc.) can sustainably support over time.", "hint": "Think about the limit imposed by an ecosystem's actual available resources."}, {"id": "sds102022", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Ecosystems — Human Impact", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best describes how human activities, such as habitat destruction, can affect biodiversity?", "options": ["human activities never have any measurable effect on biodiversity", "habitat destruction can reduce available resources and living space, often leading to population decline or species extinction", "habitat destruction always increases biodiversity in the affected area", "biodiversity is unaffected by changes to physical habitats"], "answer": 1, "exp": "Habitat destruction can reduce available resources and living space for species, often leading to population decline, increased competition, or even species extinction.", "hint": "Think about what happens to species when the physical space and resources they depend on are removed or reduced."}, {"id": "sds102023", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution — Extinction", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best describes 'extinction' in evolutionary and ecological terms?", "options": ["a temporary decline in population size that always recovers", "the complete disappearance of a species, with no living members remaining anywhere", "a process that only occurs due to direct human intervention", "a process that has never occurred throughout Earth's history"], "answer": 1, "exp": "Extinction refers to the complete disappearance of a species, meaning no living members remain anywhere on Earth.", "hint": "Think about the permanent, complete loss of every single member of a species."}, {"id": "sds102024", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution — Evidence", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best explains why studying fossils from different geological time periods helps scientists understand evolutionary change?", "options": ["fossils provide no useful chronological information", "fossils found in different rock layers, corresponding to different time periods, allow scientists to trace how species have changed over millions of years", "fossils are always exactly the same age regardless of rock layer", "fossils can only be studied in a laboratory, never in their original location"], "answer": 1, "exp": "Fossils found in different rock layers, corresponding to different geological time periods, allow scientists to trace how species have changed and diversified over millions of years.", "hint": "Think about how the AGE of different rock layers, and the fossils found within them, can reveal a timeline of change."}, {"id": "sds102025", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Evolution", "difficulty": "hard", "style": "standard", "paper": "G10-S2", "q": "Which best describes 'sexual selection' as a particular form of natural selection?", "options": ["traits that increase an individual's success in attracting mates or competing for them tend to become more common, even if not directly related to survival", "sexual selection has no connection to evolution", "only physical strength is ever favoured by sexual selection", "sexual selection only applies to plants"], "answer": 0, "exp": "Sexual selection favours traits that increase an individual's success in attracting mates or competing for them, such as bright plumage or elaborate calls, even when these traits aren't directly related to basic survival.", "hint": "Think about traits, like a peacock's tail, that exist mainly because they help attract a mate, not because they aid survival directly."}, {"id": "sds103001", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Ohm's Law", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Using Ohm's law (V = IR), find the voltage across a resistor with a current of 2 A and a resistance of 5 Ω.", "options": ["2.5 V", "7 V", "10 V", "20 V"], "answer": 2, "exp": "Step 1: V = I × R. Step 2: 2 × 5 = 10 V.", "hint": "Multiply the current by the resistance."}, {"id": "sds103002", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Ohm's Law", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Using Ohm's law, find the current flowing through a circuit with a voltage of 12 V and a resistance of 4 Ω.", "options": ["3 A", "8 A", "16 A", "48 A"], "answer": 0, "exp": "Step 1: I = V ÷ R. Step 2: 12 ÷ 4 = 3 A.", "hint": "Divide the voltage by the resistance."}, {"id": "sds103003", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Ohm's Law", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Using Ohm's law, find the resistance in a circuit with a voltage of 9 V and a current of 3 A.", "options": ["3 Ω", "6 Ω", "12 Ω", "27 Ω"], "answer": 0, "exp": "Step 1: R = V ÷ I. Step 2: 9 ÷ 3 = 3 Ω.", "hint": "Divide the voltage by the current."}, {"id": "sds103004", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Series Circuits", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Three resistors of 3 Ω, 5 Ω, and 2 Ω are connected in series. What is the total resistance?", "options": ["3.3 Ω", "6 Ω", "10 Ω", "30 Ω"], "answer": 2, "exp": "In a series circuit, total resistance is the sum of all individual resistances: 3 + 5 + 2 = 10 Ω.", "hint": "For resistors in series, simply add up all the individual resistances."}, {"id": "sds103005", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Parallel Circuits", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Two 6 Ω resistors are connected in parallel. What is the total resistance of this combination?", "options": ["3 Ω", "6 Ω", "12 Ω", "36 Ω"], "answer": 0, "exp": "Step 1: For two equal resistors in parallel, total resistance = R ÷ 2 = 6 ÷ 2. Step 2: This gives 3 Ω.", "hint": "For two identical resistors in parallel, the total resistance is half of one resistor's value."}, {"id": "sds103006", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Power", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Using the formula P = VI, find the power consumed by a device with a voltage of 12 V and a current of 3 A.", "options": ["4 W", "15 W", "36 W", "144 W"], "answer": 2, "exp": "Step 1: Power = voltage × current. Step 2: 12 × 3 = 36 W.", "hint": "Multiply the voltage by the current to find power."}, {"id": "sds103007", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Power", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Using the formula P = I²R, find the power dissipated by a resistor with a current of 2 A and a resistance of 10 Ω.", "options": ["20 W", "22 W", "40 W", "100 W"], "answer": 2, "exp": "Step 1: Power = current² × resistance. Step 2: 2² × 10 = 4 × 10 = 40 W.", "hint": "Square the current first, then multiply by the resistance."}, {"id": "sds103008", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Circuits", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Which best describes the difference between current flowing through resistors in series versus parallel?", "options": ["in series, current is the same through each resistor; in parallel, current can differ across each branch", "in series, current always differs across each resistor; in parallel, it's always identical", "current is always identical in both series and parallel circuits", "current has no real relationship to circuit arrangement"], "answer": 0, "exp": "In a series circuit, the same current flows through every component, since there's only one path. In a parallel circuit, current can divide differently across each separate branch.", "hint": "Think about the number of paths current can take in each type of circuit."}, {"id": "sds103009", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Circuits", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Which best describes the difference between voltage across resistors in series versus parallel?", "options": ["in series, voltage divides across each resistor; in parallel, voltage is the same across each branch", "in series, voltage is always identical across each resistor; in parallel, voltage always divides", "voltage has no real relationship to circuit arrangement", "voltage and current always behave identically in any circuit"], "answer": 0, "exp": "In a series circuit, voltage divides across each resistor according to its resistance. In a parallel circuit, each branch experiences the same voltage as the total supply.", "hint": "Think about how the total voltage is 'shared out' differently depending on the circuit type."}, {"id": "sds103010", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Speed", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "A wave has a frequency of 50 Hz and a wavelength of 4 m. What is its speed?", "options": ["12.5 m/s", "54 m/s", "200 m/s", "400 m/s"], "answer": 2, "exp": "Step 1: Wave speed = frequency × wavelength. Step 2: 50 × 4 = 200 m/s.", "hint": "Multiply the frequency by the wavelength."}, {"id": "sds103011", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Frequency", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "A sound wave travels at 340 m/s with a wavelength of 0.5 m. What is its frequency?", "options": ["170 Hz", "340 Hz", "680 Hz", "1700 Hz"], "answer": 2, "exp": "Step 1: Frequency = speed ÷ wavelength. Step 2: 340 ÷ 0.5 = 680 Hz.", "hint": "Divide the wave's speed by its wavelength."}, {"id": "sds103012", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Period", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "A wave has a frequency of 20 Hz. What is its period (the time for one complete wave cycle)?", "options": ["0.05 s", "0.2 s", "2 s", "20 s"], "answer": 0, "exp": "Step 1: Period = 1 ÷ frequency. Step 2: 1 ÷ 20 = 0.05 s.", "hint": "Take the reciprocal of the frequency to find the period."}, {"id": "sds103013", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Which best describes the difference between a transverse wave and a longitudinal wave?", "options": ["in a transverse wave, particles vibrate perpendicular to the direction of travel; in a longitudinal wave, they vibrate parallel to it", "both wave types vibrate in exactly the same direction", "transverse waves can only travel through solids", "longitudinal waves can only travel through a vacuum"], "answer": 0, "exp": "In a transverse wave (like light), particles vibrate perpendicular (at right angles) to the direction the wave travels. In a longitudinal wave (like sound), particles vibrate parallel to the direction of travel.", "hint": "Think about the angle between the particle vibration and the wave's direction of travel."}, {"id": "sds103014", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Which of these is an example of a longitudinal wave?", "options": ["light waves", "sound waves", "radio waves", "visible light"], "answer": 1, "exp": "Sound waves are longitudinal waves, with particles vibrating back and forth parallel to the direction the wave travels.", "hint": "Think about the wave type where particles compress and expand along the same direction as the wave."}, {"id": "sds103015", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Types", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Which of these is an example of a transverse wave?", "options": ["sound waves", "light waves", "seismic P-waves", "none of these are transverse waves"], "answer": 1, "exp": "Light waves are transverse waves, with vibrations occurring perpendicular to the direction the wave travels.", "hint": "Think about the wave type where the vibration direction is at right angles to the direction of travel."}, {"id": "sds103016", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Properties", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "What is the 'amplitude' of a wave?", "options": ["the time taken for one complete cycle", "the maximum displacement of a particle from its rest position", "the number of waves passing a point per second", "the speed at which the wave travels"], "answer": 1, "exp": "Amplitude is the maximum displacement of a particle from its rest (equilibrium) position, related to the energy or intensity of the wave.", "hint": "Think about how far a particle moves from its 'resting' position at the wave's highest or lowest point."}, {"id": "sds103017", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Properties", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "What is the 'wavelength' of a wave?", "options": ["the maximum displacement of a particle", "the distance between two consecutive identical points on a wave, such as crest to crest", "the number of waves passing a point per second", "the time taken for one complete wave cycle"], "answer": 1, "exp": "Wavelength is the distance between two consecutive identical points on a wave, such as from one crest to the next crest.", "hint": "Think about measuring the distance for one full repeating pattern of the wave."}, {"id": "sds103018", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Relationships", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "How would increasing the frequency of a wave, while keeping its speed constant, affect its wavelength?", "options": ["wavelength would increase", "wavelength would decrease", "wavelength would remain exactly the same", "frequency and wavelength have no relationship"], "answer": 1, "exp": "Since wave speed = frequency × wavelength, if speed stays constant and frequency increases, wavelength must decrease proportionally.", "hint": "Think about the relationship between speed, frequency, and wavelength — if speed stays the same, increasing one must decrease the other."}, {"id": "sds103019", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Parallel Circuits", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "What happens to the total resistance of a circuit when an additional resistor is added in parallel to existing resistors?", "options": ["the total resistance increases", "the total resistance decreases", "the total resistance stays exactly the same", "total resistance becomes impossible to calculate"], "answer": 1, "exp": "Adding an additional resistor in parallel provides another path for current to flow, which decreases the overall total resistance of the circuit.", "hint": "Think about how adding another 'path' for current might affect the overall resistance to its flow."}, {"id": "sds103020", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Series Circuits", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "What happens to the total resistance of a circuit when an additional resistor is added in series with existing resistors?", "options": ["the total resistance increases", "the total resistance decreases", "the total resistance stays exactly the same", "total resistance becomes impossible to calculate"], "answer": 0, "exp": "Adding an additional resistor in series increases the total resistance, since the current must now pass through more resistance along the single available path.", "hint": "Think about adding another obstacle along the single path current must travel through."}, {"id": "sds103021", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Ohm's Law", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "A circuit has a 9 V battery and a total resistance of 3 Ω. What is the total current flowing in the circuit?", "options": ["0.33 A", "3 A", "12 A", "27 A"], "answer": 1, "exp": "Step 1: I = V ÷ R. Step 2: 9 ÷ 3 = 3 A.", "hint": "Divide the voltage by the total resistance."}, {"id": "sds103022", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Behaviour", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Which best describes 'reflection' as it applies to waves?", "options": ["a wave bouncing off a surface and changing direction", "a wave bending as it passes from one medium into another", "a wave's energy being completely absorbed", "two waves combining into one larger wave"], "answer": 0, "exp": "Reflection occurs when a wave bounces off a surface, changing direction while remaining in the same medium.", "hint": "Think about a wave bouncing back, similar to how light reflects off a mirror."}, {"id": "sds103023", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Behaviour", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Which best describes 'refraction' as it applies to waves?", "options": ["a wave bouncing directly back off a surface", "a wave changing direction (bending) as it passes from one medium into another, due to a change in speed", "a wave disappearing completely", "two waves cancelling each other out"], "answer": 1, "exp": "Refraction occurs when a wave changes direction as it passes from one medium into another, caused by a change in the wave's speed in the new medium.", "hint": "Think about a wave bending as it enters a new material, due to a change in speed."}, {"id": "sds103024", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Waves — Behaviour", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "Which best describes 'diffraction' as it applies to waves?", "options": ["a wave's complete disappearance after hitting an obstacle", "the spreading out of a wave as it passes through a gap or around an obstacle", "a wave reversing its direction completely", "a wave converting entirely into a different type of energy"], "answer": 1, "exp": "Diffraction is the spreading out of a wave as it passes through a narrow gap or around an obstacle, becoming more noticeable when the gap size is similar to the wavelength.", "hint": "Think about a wave 'bending around' an obstacle or spreading out after passing through a narrow opening."}, {"id": "sds103025", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Electricity — Ohm's Law", "difficulty": "hard", "style": "standard", "paper": "G10-S3", "q": "A circuit contains a 6 V battery and a single resistor. If the current is measured at 1.5 A, what is the resistance?", "options": ["2 Ω", "4 Ω", "9 Ω", "12 Ω"], "answer": 1, "exp": "Step 1: R = V ÷ I. Step 2: 6 ÷ 1.5 = 4 Ω.", "hint": "Divide the voltage by the current to find the resistance."}, {"id": "sds104001", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Sample Size", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A scientist designs an experiment with a sample size of only 5 participants, due to time constraints. What is the main limitation of drawing strong conclusions from this study?", "options": ["there is no real limitation with a small sample size", "a small sample size increases the risk that results are due to chance or individual variation, rather than reflecting a genuine, generalisable pattern", "small sample sizes always produce more accurate results than large ones", "sample size has no connection to the reliability of conclusions"], "answer": 1, "exp": "A small sample size increases the risk that results reflect chance or unusual individual variation, rather than a genuine, generalisable pattern that would apply more broadly.", "hint": "Think about how a handful of unusual individual results might more easily distort findings from a small sample, compared to a large one."}, {"id": "sds104002", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Errors", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best describes a 'systematic error' in an experiment, as opposed to a 'random error'?", "options": ["a systematic error occurs randomly and unpredictably each time", "a systematic error consistently affects results in the same direction, often due to a flaw in equipment or method, while random errors vary unpredictably", "systematic and random errors are exactly the same thing", "systematic errors can never be identified or corrected"], "answer": 1, "exp": "A systematic error consistently affects results in the same direction (such as a miscalibrated instrument always reading too high), while random errors vary unpredictably from trial to trial.", "hint": "Think about an error that happens the SAME way every time, often due to equipment or method, versus one that varies unpredictably."}, {"id": "sds104003", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Measurement", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Why is it important to calibrate scientific instruments before use?", "options": ["calibration has no real effect on measurement accuracy", "calibration helps ensure an instrument provides accurate readings, reducing the risk of systematic error", "calibration is only relevant for instruments used in physics", "calibrated instruments always produce completely random results"], "answer": 1, "exp": "Calibration helps ensure an instrument provides accurate readings, comparing it against a known standard, which reduces the risk of consistent (systematic) measurement errors.", "hint": "Think about checking an instrument against a known, trusted standard before relying on its readings."}, {"id": "sds104004", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Generalisability", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A study finds that a new fertiliser increases plant growth in a laboratory setting. Why might the results not necessarily apply directly to a real outdoor farm?", "options": ["laboratory results are always identical to real-world conditions", "laboratory conditions (controlled temperature, light, soil) may differ significantly from variable real-world farm conditions, limiting direct generalisation", "laboratory experiments are never scientifically valid", "fertiliser only works in laboratory settings"], "answer": 1, "exp": "Controlled laboratory conditions may differ significantly from the variable conditions (weather, soil type, pests) found on a real outdoor farm, which can limit how directly laboratory findings generalise to real-world settings.", "hint": "Think about what factors might differ between a tightly controlled lab environment and an unpredictable outdoor farm."}, {"id": "sds104005", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Meta-Analysis", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best describes the purpose of a 'meta-analysis' in scientific research?", "options": ["a meta-analysis is simply one researcher's personal opinion", "a meta-analysis combines and statistically analyses results from multiple independent studies, often providing stronger overall evidence than any single study alone", "meta-analyses are never considered reliable in science", "a meta-analysis always contradicts the findings of individual studies"], "answer": 1, "exp": "A meta-analysis combines and statistically analyses results from multiple independent studies on the same question, often providing stronger, more reliable overall evidence than any single study could alone.", "hint": "Think about combining the results of MANY separate studies into one larger, more powerful analysis."}, {"id": "sds104006", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Research Ethics", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A researcher reports only the results that supported their initial hypothesis, while omitting other, less favourable data collected during the same study. What is this practice called, and why is it problematic?", "options": ["this is good scientific practice and should be encouraged", "this is a form of selective reporting (or 'cherry-picking'), which can mislead readers about the true, complete picture of the evidence", "this practice has no real effect on how a study is interpreted", "scientific journals never check for this kind of practice"], "answer": 1, "exp": "This is selective reporting (or 'cherry-picking'), which can seriously mislead readers by presenting an incomplete, biased picture of the actual evidence collected.", "hint": "Think about the term for only sharing the results that support what you wanted to find, while hiding the rest."}, {"id": "sds104007", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Nature of Science", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best describes why scientific theories, such as evolution by natural selection, are considered well-supported despite being called 'theories' rather than 'facts' or 'laws'?", "options": ["the word 'theory' in science means an unproven guess, identical to its everyday casual usage", "in science, a 'theory' is a thoroughly tested, well-substantiated explanation supported by a large body of evidence, distinct from the casual everyday use of the word", "scientific theories are always eventually proven completely wrong", "theories and hypotheses mean exactly the same thing in science"], "answer": 1, "exp": "In science, a 'theory' refers to a thoroughly tested, well-substantiated explanation supported by extensive evidence — quite different from the everyday casual use of 'theory' to mean an unproven guess.", "hint": "Think about the specific, technical scientific meaning of 'theory', which differs significantly from its casual, everyday use."}, {"id": "sds104008", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Experimental Design", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A drug trial uses a randomised, double-blind, placebo-controlled design. What is the main purpose of randomly assigning participants to treatment groups?", "options": ["randomisation serves no real scientific purpose", "randomisation helps ensure that any differences between groups (other than the treatment itself) are due to chance, rather than systematic bias in how participants were selected", "randomisation guarantees that the drug will be effective", "randomisation is only used in studies involving animals, not humans"], "answer": 1, "exp": "Random assignment helps ensure that any differences between treatment groups occur by chance, rather than from a systematic bias in how participants happened to be selected or grouped.", "hint": "Think about why randomly assigning people (rather than letting them choose, or assigning them deliberately) helps make a fair comparison between groups."}, {"id": "sds104009", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Replication", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Why might a scientific study be considered more credible if it has been replicated by independent researchers in different locations?", "options": ["replication has no real bearing on scientific credibility", "successful replication by independent researchers suggests the original finding is robust and not simply due to a single research team's error, bias, or unique circumstances", "studies are never replicated in real scientific practice", "replication always proves an original finding was completely wrong"], "answer": 1, "exp": "Successful replication by independent researchers, often in different locations or with different participants, suggests the original finding is robust and not simply the result of one team's specific error, bias, or unique circumstances.", "hint": "Think about why a result holding up across multiple, independent attempts adds confidence beyond a single original study."}, {"id": "sds104010", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Data Analysis", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A graph shows data with error bars representing the range of uncertainty in each measurement. What does it generally suggest if the error bars of two data points overlap significantly?", "options": ["the two values are definitely completely different from each other", "the difference between the two values may not be statistically significant, given the overlapping uncertainty", "error bars have no real meaning in scientific graphs", "overlapping error bars always indicate a measurement mistake"], "answer": 1, "exp": "Significantly overlapping error bars suggest that the difference between two values may not be statistically significant, since the true values could reasonably fall within a similar range given the measurement uncertainty.", "hint": "Think about what overlapping ranges of uncertainty suggest about whether two measurements are genuinely, reliably different."}, {"id": "sds104011", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Confounding Variables", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best describes 'confounding variables' in an investigation?", "options": ["variables that have no effect on the outcome being measured", "variables other than the one being tested that could also influence the outcome, potentially leading to misleading conclusions if not properly controlled", "a type of equipment used only in chemistry experiments", "confounding variables only exist in poorly designed studies, never in well-designed ones"], "answer": 1, "exp": "Confounding variables are factors other than the one being tested that could also influence the outcome, potentially leading to misleading conclusions if they are not properly identified and controlled for.", "hint": "Think about an additional, uncontrolled factor that could be the 'real' explanation for a result, rather than the variable actually being tested."}, {"id": "sds104012", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Confounding Variables", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A study observes that ice cream sales and drowning incidents both increase in summer. Why would it be a confounding variable error to conclude that ice cream sales cause drowning?", "options": ["this is actually a completely valid scientific conclusion", "both variables are likely independently influenced by warmer weather (more swimming and more ice cream consumption), rather than one directly causing the other", "ice cream genuinely causes drowning, according to this evidence", "drowning incidents have no real connection to weather at all"], "answer": 1, "exp": "Both ice cream sales and drowning incidents are likely independently influenced by warmer weather (which increases both swimming and ice cream consumption), rather than ice cream sales directly causing drowning.", "hint": "Think about a third factor (the season) that could independently explain both trends, without one causing the other."}, {"id": "sds104013", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Evaluating Sources", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best describes why peer-reviewed scientific journals are generally considered more reliable sources than non-peer-reviewed websites?", "options": ["peer review guarantees a study contains absolutely no errors", "peer review involves independent expert evaluation before publication, which helps filter out seriously flawed methodology or unsupported claims, though it isn't a perfect guarantee of accuracy", "peer-reviewed journals are always free to access, unlike websites", "there is no real difference in reliability between these two types of sources"], "answer": 1, "exp": "Peer review involves independent expert evaluation before publication, helping to filter out seriously flawed methodology or unsupported claims — though it remains an imperfect process, not an absolute guarantee of accuracy.", "hint": "Think about the additional layer of expert scrutiny that peer-reviewed sources generally go through before publication."}, {"id": "sds104014", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Data Analysis", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best describes 'extrapolation' when interpreting data from a graph?", "options": ["reading a value directly from within the range of collected data", "estimating a value beyond the range of the actual data collected, which carries greater uncertainty than reading within the data's range", "extrapolation is always exactly as reliable as data taken directly from measurements", "extrapolation can never be used in any scientific context"], "answer": 1, "exp": "Extrapolation involves estimating a value beyond the range of actual data collected, which carries greater uncertainty than reading a value that falls within the range of data actually measured.", "hint": "Think about predicting a value PAST the edge of your actual collected data, rather than reading a value from within that range."}, {"id": "sds104015", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Conflicts of Interest", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A pharmaceutical company funds a study testing its own new drug, and the study finds the drug to be highly effective with minimal side effects. Why might this funding source be considered a potential limitation when evaluating the study, even if the methodology appears sound?", "options": ["company-funded research is always automatically invalid and should be ignored entirely", "a funding source with a strong financial interest in a particular outcome represents a potential conflict of interest, which should be disclosed and considered alongside the study's methodology", "funding sources have no possible connection to a study's design or interpretation", "disclosing funding sources is not standard practice in scientific publishing"], "answer": 1, "exp": "A funding source with a strong financial interest in a particular outcome represents a potential conflict of interest, which doesn't automatically invalidate the findings, but should be disclosed and considered alongside an evaluation of the study's actual methodology.", "hint": "Think about why knowing who funded a study, and their potential interest in a specific result, is relevant information for readers — without automatically dismissing the findings."}, {"id": "sds104016", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Hypothesis Testing", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best describes the value of a 'null hypothesis' in a scientific investigation?", "options": ["a null hypothesis always states that the experiment will definitely succeed", "a null hypothesis typically proposes that there is no real effect or difference, providing a baseline that the actual results can be tested against", "null hypotheses are never used in real scientific research", "a null hypothesis is identical to the researcher's actual prediction"], "answer": 1, "exp": "A null hypothesis typically proposes that there is no real effect or difference (e.g., 'this fertiliser has no effect on plant growth'), providing a baseline that the actual experimental results can be statistically tested against.", "hint": "Think about a 'default' assumption of no effect, which the experiment then tries to provide evidence against."}, {"id": "sds104017", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Study Design", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Why might a longitudinal study (following the same participants over many years) provide different insights than a cross-sectional study (comparing different groups at one point in time)?", "options": ["longitudinal studies and cross-sectional studies always produce identical results", "longitudinal studies can track actual changes within the same individuals over time, while cross-sectional studies only provide a snapshot comparison across different individuals at one moment", "cross-sectional studies are always more reliable than longitudinal studies", "longitudinal studies can only be conducted on animals, never humans"], "answer": 1, "exp": "Longitudinal studies can track actual changes within the same individuals over an extended period, while cross-sectional studies only provide a single snapshot comparison across different individuals at one specific point in time.", "hint": "Think about the difference between following the SAME people over time, versus comparing DIFFERENT people all at once."}, {"id": "sds104018", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Scientific Method — Sample Diversity", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best describes why it's important for scientists to consider sample diversity (e.g. age, gender, background) when designing a study intended to apply to the general population?", "options": ["sample diversity has no real bearing on how broadly findings can be applied", "findings from a narrow, unrepresentative sample may not generalise well to the broader population the conclusions are intended to describe", "studies should always use the narrowest possible sample for accuracy", "diverse samples always produce less reliable results than narrow ones"], "answer": 1, "exp": "Findings from a narrow, unrepresentative sample (such as only one age group or background) may not generalise well to the broader population the study's conclusions are intended to describe.", "hint": "Think about whether a finding based on a very specific, narrow group of people can be fairly applied to everyone."}, {"id": "sds104019", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Integrated Review — Density", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A 500 g object has a density of 2.5 g/mL. What is its volume?", "options": ["100 mL", "125 mL", "200 mL", "1250 mL"], "answer": 2, "exp": "Step 1: Volume = mass ÷ density. Step 2: 500 ÷ 2.5 = 200 mL.", "hint": "Rearrange the density formula (density = mass ÷ volume) to solve for volume."}, {"id": "sds104020", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Integrated Review — Electricity", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A circuit has a voltage of 24 V and a current of 4 A. What is the power consumed?", "options": ["6 W", "20 W", "28 W", "96 W"], "answer": 3, "exp": "Step 1: Power = voltage × current. Step 2: 24 × 4 = 96 W.", "hint": "Multiply the voltage by the current."}, {"id": "sds104021", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Integrated Review — Decay", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A radioactive isotope has a half-life of 8 years. Starting with 160 g, how much remains after 24 years?", "options": ["10 g", "20 g", "40 g", "80 g"], "answer": 1, "exp": "Step 1: 24 years represents 3 half-lives (24÷8=3). Step 2: Mass = 160 × (0.5)³ = 160 × 0.125 = 20 g.", "hint": "Work out how many half-lives have passed, then halve the mass that many times."}, {"id": "sds104022", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Integrated Review — Evolution", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best summarises the relationship between genetic mutation, natural selection, and evolution over time?", "options": ["mutations have no real connection to evolution", "random mutations create genetic variation, and natural selection then acts on this variation, favouring traits that improve survival and reproduction, gradually leading to evolutionary change", "natural selection creates mutations directly", "evolution occurs without any genetic basis at all"], "answer": 1, "exp": "Random mutations create genetic variation within a population, and natural selection then acts on this variation, favouring traits that improve survival and reproduction — gradually leading to evolutionary change over many generations.", "hint": "Think about how these three concepts connect in sequence: variation arising, then selection acting on it, leading to change over time."}, {"id": "sds104023", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Integrated Review — Body Systems", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best summarises why both the nervous and endocrine systems are important for maintaining homeostasis in the human body?", "options": ["only the nervous system has any role in homeostasis", "the nervous system enables rapid responses to changes, while the endocrine system provides longer-lasting regulation, together helping maintain a stable internal environment", "only the endocrine system has any role in homeostasis", "homeostasis has no connection to either of these body systems"], "answer": 1, "exp": "The nervous system enables rapid responses to changes (such as reflexes), while the endocrine system provides longer-lasting regulation (such as blood sugar control), together helping maintain a stable internal environment (homeostasis).", "hint": "Think about how combining a fast-acting system with a slower, longer-lasting system helps the body adjust to both immediate and ongoing changes."}, {"id": "sds104024", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Integrated Review — Energy", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "Which best summarises the relationship between an exothermic reaction and the conservation of energy?", "options": ["exothermic reactions create new energy that did not previously exist", "exothermic reactions release stored chemical energy as heat, with total energy before and after the reaction remaining conserved overall", "exothermic reactions destroy energy completely", "conservation of energy does not apply to chemical reactions"], "answer": 1, "exp": "Exothermic reactions release stored chemical energy as heat into the surroundings, but the total energy before and after the reaction remains conserved overall — energy changes form rather than being created or destroyed.", "hint": "Think about energy simply changing form (from stored chemical energy to heat), rather than being created or destroyed."}, {"id": "sds104025", "state": "AU", "section": "sec_science", "grade": "10", "topic": "Integrated Review — Scientific Method", "difficulty": "hard", "style": "standard", "paper": "G10-S4", "q": "A student investigating plant growth under different light colours fails to control for water amount, accidentally giving the red-light group more water than the blue-light group. Why does this undermine the investigation's conclusions about light colour?", "options": ["it doesn't undermine the conclusions at all, since light colour was the only thing being tested intentionally", "water amount becomes a confounding variable, making it impossible to know whether differences in growth are due to light colour, water amount, or both", "extra water always has no effect on plant growth", "this kind of error is impossible to avoid in any experiment"], "answer": 1, "exp": "Water amount becomes a confounding variable in this case, making it impossible to confidently attribute any growth differences specifically to light colour, since water amount also differed between the groups.", "hint": "Think about how an unintentional difference in another variable can make it impossible to isolate the effect of the variable actually being tested."}];